    REFERENCES batch_step_execution(STEP_EXECUTION_ID);


-- deployment: Creating batch_job_seq...
CREATE TABLE batch_job_seq (
    ID bigint NOT NULL
);


-- deployment: Creating batch_job_instance...
CREATE TABLE batch_job_instance (
    JOB_INSTANCE_ID bigint NOT NULL,
    VERSION bigint NULL,
    JOB_NAME varchar(100) NOT NULL,
    JOB_KEY varchar(32) NOT NULL
);
ALTER TABLE batch_job_instance ADD PRIMARY KEY (JOB_INSTANCE_ID);


-- deployment: Creating batch_job_execution_seq...
CREATE TABLE batch_job_execution_seq (
    ID bigint NOT NULL
);


-- deployment: Creating batch_job_execution_params...
CREATE TABLE batch_job_execution_params (
    JOB_EXECUTION_ID bigint NOT NULL,
    PARAMETER_NAME varchar(100) NOT NULL,
    PARAMETER_TYPE varchar(100) NOT NULL,
    PARAMETER_VALUE varchar(2500) NULL,
    IDENTIFYING char(1) NOT NULL
);


-- deployment: Creating batch_job_execution_context...
CREATE TABLE batch_job_execution_context (
    JOB_EXECUTION_ID bigint NOT NULL,
    SHORT_CONTEXT varchar(2500) NOT NULL,
    SERIALIZED_CONTEXT text NULL
);
ALTER TABLE batch_job_execution_context ADD PRIMARY KEY (JOB_EXECUTION_ID);


-- deployment: Creating batch_job_execution...
CREATE TABLE batch_job_execution (
    JOB_EXECUTION_ID bigint NOT NULL,
    VERSION bigint NULL,
    JOB_INSTANCE_ID bigint NOT NULL,
    CREATE_TIME timestamp NOT NULL,
    START_TIME timestamp NULL,
    END_TIME timestamp NULL,
    STATUS varchar(10) NULL,
    EXIT_CODE varchar(20) NULL,
    EXIT_MESSAGE varchar(2500) NULL,
    LAST_UPDATED timestamp NULL
);
ALTER TABLE batch_job_execution ADD PRIMARY KEY (JOB_EXECUTION_ID);


-- deployment: Creating batch_job_execution_context.JOB_EXEC_CTX_FK...
ALTER TABLE batch_job_execution_context
    ADD CONSTRAINT JOB_EXEC_CTX_FK FOREIGN KEY (JOB_EXECUTION_ID)
    REFERENCES batch_job_execution(JOB_EXECUTION_ID);


-- deployment: Creating sp_test_create_order...
CREATE PROCEDURE sp_test_create_order (IN order_json json)
BEGIN
    DECLARE v_order_id BIGINT;
    DECLARE i INT DEFAULT 0;
    DECLARE item_count INT DEFAULT 0;
    DECLARE v_shipping_address_id BIGINT DEFAULT NULL;
	DECLARE v_billing_address_id BIGINT DEFAULT NULL;
    DECLARE v_order_num varchar(50);
    DECLARE v_return_order varchar(10);
    DECLARE v_returnable tinyint;
	DECLARE payment_retry INT DEFAULT 0;
    DECLARE current_date_time datetime;
	DECLARE retry_payment_time datetime;
    DECLARE v_total_item_weight DECIMAL(10,2);
    
    DECLARE v_item_id varchar(50);
    DECLARE v_inventory_model varchar(50);
    
    DECLARE v_item_title VARCHAR(255) ;
	DECLARE v_item_image VARCHAR(500);
	DECLARE v_item_slug VARCHAR(255) ;
	DECLARE v_unit_mrp DECIMAL(10,2);
    DECLARE v_unit_price DECIMAL(10,2);
	DECLARE v_tax_amt DECIMAL(10,2);

    START TRANSACTION;
    set v_order_num=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.orderNum')),'null'),'');
	--  if not exists(select 1 from chs_ecom_sales_order_master where order_num=v_order_num)
    -- actual if start
    if v_order_num is null
    then
    
     SET v_order_num = UPPER(SUBSTRING(UUID(), 1, 6));


   WHILE EXISTS (SELECT 1 FROM chs_ecom_sales_order_master WHERE order_num = v_order_num) DO
   SET v_order_num = UPPER(SUBSTRING(UUID(), 1, 6));END WHILE;

    
	SET payment_retry=(SELECT param_value FROM chs_core_settings_code_details WHERE code_id=2 AND param_key="RETRY_PAYMENT_MINUTES");
	SET current_date_time = now();
    SET retry_payment_time = DATE_ADD(current_date_time, INTERVAL payment_retry MINUTE);
    INSERT INTO chs_ecom_sales_order_master(
		order_num, 
        cpg_order_id,
        username, 
        customer_id, 
        order_status, 
        total_price,
        total_mrp,
        final_price,
        total_items,
        total_qty,
        disc_amount, 
        coupon_disc_amount,
        tax_amount, 
        shipping_charge, 
        payment_status, 
        payment_method,
        retry_payment_time,
      --  billing_address_id,
        placed_on,
        is_wallet_included, 
		wallet_txn_id,
		wallet_amount, 
		amount,
		wallet_debit_type
    ) VALUES (
        v_order_num,
        -- concat(SUBSTRING_INDEX(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.username')),'null'),''), '-', -1),DATE_FORMAT(NOW(), '%Y%m%d%H%i%s')),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.cpgOrderId')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.username')),'null'),''),
        (select id from chs_ecom_customer_customer where username=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.username')),'null'),'')),
        'PENDING',
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.totalPrice')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.totalMrp')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.finalPrice')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.totalItems')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.totalQty')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.discAmount')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.taxAmount')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.shippingCharge')),'null'),''),
        'PENDING',
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentMethod')),'null'),''),
      --  NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.billingAddressId')),'null'),''),
        retry_payment_time,
        current_date_time,
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletInclude')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletTxnId')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletAmount')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.amount')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletDebitType')),'null'),'')
    );
    
    SET v_order_id = LAST_INSERT_ID();
    
    INSERT INTO chs_ecom_sales_order_workflow
    (
		order_id, 
        from_status, 
        to_status, 
        changed_on, 
        changed_by, 
        notes
    ) VALUES (
		v_order_id,
        'PENDING',
		'PENDING',
		now(),
        'system',
        'Order has been successfully placed'
    );
     
    INSERT INTO chs_ecom_sales_order_shipping
    (
		order_id, 
        -- shipping_address_id, 
        method, 
        tracking_number, 
        carrier, 
        est_delivery_date, 
        shipping_charge, 
        created_on
    )
    values (
		v_order_id,
        -- NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.shippingAddressId')),'null'),''),
        'STANDARD',
        concat(SUBSTRING_INDEX(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.username')),'null'),''), '-', -1),DATE_FORMAT(NOW(), '%Y%m%d%H%i%s')),
        null,
        DATE_ADD(CURDATE(), INTERVAL 7 DAY),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.shippingCharge')),'null'),''),
        now()
    );
    
        INSERT INTO chs_ecom_sales_order_discounts
    (
		order_id, 
        disc_code, 
        coupon_txn_id, 
        disc_value, 
        created_at
    )
    values (
		v_order_id, 
		(select discount_code from chs_core_marketing_discount_usage where  discount_txn_id= NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),'')),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),'null'),''),
        now()
    );
    
    set v_inventory_model= (NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.inventoryModel')),'null'),''));
    SET i = 0;
SET item_count = JSON_LENGTH(order_json, '$.checkoutDetails.checkoutItems');

WHILE i < item_count DO
 SET v_item_id = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].itemId'))), 'null'), '');
    -- SET @v_qty = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].qty'))), 'null'), '');

	SELECT item_title,item_image,item_slug,item_mrp,item_price
INTO v_item_title,v_item_image,v_item_slug,v_unit_mrp,v_unit_price
FROM chs_ecom_pms_product_card
WHERE item_id = v_item_id 
and inventory_model= v_inventory_model;


    -- Extract returnAllowed (a BOOLEAN value in JSON)
    SET v_return_order = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].returnAllowed'))), 'null'), '');
    SET v_returnable = CASE WHEN v_return_order = 'true' THEN 1 ELSE 0 END;

    INSERT INTO chs_ecom_sales_order_items (
        order_id,
        product_id,
        item_id,
		item_title ,
		item_image ,
		item_slug ,
        batch_id,
        qty,
        unit_price,
        unit_mrp,
        volume_unit_price,
        volume_unit_mrp,
        tax_amt,
        disc_amount,
        total_price,
        total_mrp,
        return_allowed
    ) VALUES (
        v_order_id,
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].productId'))), 'null'), ''),
        v_item_id,
        
        
       v_item_title,v_item_image,v_item_slug,
        
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].batchId'))), 'null'), ''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].qty'))), 'null'), ''),
        
		v_unit_price,v_unit_mrp,
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].volumeUnitPrice'))), 'null'), ''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].volumeUnitMrp'))), 'null'), ''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].taxAmt'))), 'null'), ''),

        
        
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].discAmount'))), 'null'), ''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].totalPrice'))), 'null'), ''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].totalMrp'))), 'null'), ''),
        v_returnable
    );

    SET i = i + 1;

END WHILE;

-- SET v_total_item_weight = (
 --   SELECT SUM(pi.weight_in_gms * oi.qty) FROM chs_ecom_sales_order_items oi
 --   JOIN chs_ecom_pms_product_item pi ON oi.item_id = pi.id WHERE oi.order_id = v_order_id);

UPDATE chs_ecom_sales_order_master SET order_weight = v_total_item_weight WHERE id = v_order_id;



    case when JSON_EXTRACT(order_json, '$.shippingAddressId') <> JSON_EXTRACT(order_json, '$.billingAddressId') then
     INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.shippingAddressId');
    SET v_shipping_address_id = LAST_INSERT_ID();

   INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.billingAddressId');
    SET v_billing_address_id = LAST_INSERT_ID();
    
    else 
    INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.shippingAddressId');
    SET v_shipping_address_id = LAST_INSERT_ID();
    set v_billing_address_id = v_shipping_address_id;
    
    end case;
    
INSERT INTO chs_ecom_sales_order_address (
    order_id,
    shipping_address_id,
    billing_address_id
) VALUES (
    v_order_id,
    v_shipping_address_id,
    v_billing_address_id
);
	
    INSERT INTO chs_ecom_sales_order_summary (
    order_num,
    username,
    customer_id,
    full_name,
    email,
    mobile_num,
    order_status,
    total_mrp,
    final_price,
    coupon_disc_amount,
    total_price,
    disc_amount,
    tax_amount,
    shipping_charge,
    payment_status,
    payment_method,
    invoice_url,
    placed_on,
    billing_address,
    shipping_address
)
SELECT 
    om.order_num,
    om.username,
    om.customer_id,
    c.full_name,
    c.email_id,
    c.mobile_number,
    om.order_status,
    om.total_mrp,
    om.final_price,
    om.coupon_disc_amount,
    om.total_price,
    om.disc_amount,
    om.tax_amount,
    om.shipping_charge,
    om.payment_status,
    om.payment_method,
    NULL AS invoice_url,
    om.placed_on,

    -- Billing Address JSON
    (SELECT JSON_OBJECT(
        'fullName', a.full_name,
        'phoneNumber', a.phone_number,
        'addressLine1', a.address_line1,
        'addressLine2', a.address_line2,
        'city', a.city,
        'state', a.state,
        'country', a.country,
        'postalCode', a.postal_code
    )
    FROM chs_core_utils_address_master a 
    WHERE a.id = oa.billing_address_id),

    -- Shipping Address JSON
    (SELECT JSON_OBJECT(
        'fullName', a.full_name,
        'phoneNumber', a.phone_number,
        'addressLine1', a.address_line1,
        'addressLine2', a.address_line2,
        'city', a.city,
        'state', a.state,
        'country', a.country,
        'postalCode', a.postal_code
    )
    FROM chs_core_utils_address_master a 
    WHERE a.id = oa.shipping_address_id)

FROM chs_ecom_sales_order_master om
left JOIN chs_ecom_customer_customer_summary c ON c.id = om.customer_id
JOIN chs_ecom_sales_order_address oa ON oa.order_id = om.id
WHERE om.id = v_order_id;

    
    IF JSON_EXTRACT(order_json, '$.checkoutDetails.cartId') IS NOT NULL THEN
    delete from chs_ecom_sales_cart_items where cart_id=(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.cartId')),'null'),''));
    delete from chs_ecom_sales_cart where id=(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.cartId')),'null'),''));
    end if;
    
    
    
    -- Actual else case
    else if exists(select 1 from chs_ecom_sales_order_master where order_num=v_order_num) then
    set v_order_id=(select id from chs_ecom_sales_order_master where order_num=v_order_num);
    if not exists(select 1 from chs_ecom_sales_order_master where id=v_order_id and 
    payment_method=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentMethod')),'null'),'')) then
    update chs_ecom_sales_order_master
    set payment_method=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentMethod')),'null'),'') where id=v_order_id;
    end if;
    
    if not exists(select 1 from chs_ecom_sales_order_discounts where order_id=v_order_id and coupon_txn_id=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),''))
    then
    update chs_ecom_sales_order_discounts
    set coupon_txn_id=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),''), 
    disc_code=(select discount_code from discount_usage
    where discount_txn_id= NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),''))
	,disc_value= NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),'null'),'')
	where order_id=v_order_id;
    
    update chs_ecom_sales_order_master
    set final_price=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.finalPrice')),'null'),'')
    ,coupon_disc_amount=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),'null'),'')
    ,amount = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.amount')),'null'),'')
    ,cpg_order_id = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.cpgOrderId')),'null'),'')
    ,wallet_txn_id = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletTxnId')),'null'),'')
    ,wallet_debit_type = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletDebitType')),'null'),'')
    ,wallet_amount = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletAmount')),'null'),'')
    ,payment_status = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentStatus')),'null'),'')
    where id=v_order_id;
    end if;
    
    if exists (select 1 from chs_ecom_sales_order_address where JSON_EXTRACT(order_json, '$.billingAddressId')=JSON_EXTRACT(order_json, '$.shippingAddressId') 
    and order_id=v_order_id and (JSON_EXTRACT(order_json, '$.billingAddressId')<>billing_address_id or JSON_EXTRACT(order_json, '$.shippingAddressId')<>shipping_address_id))
    then 
    INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.shippingAddressId');
    SET v_shipping_address_id = LAST_INSERT_ID();
    set v_billing_address_id = v_shipping_address_id;
	
update chs_ecom_sales_order_address
set shipping_address_id=v_shipping_address_id , billing_address_id=v_billing_address_id
where order_id=v_order_id;
		
        else 
        if exists (select 1 from chs_ecom_sales_order_address where order_id=v_order_id and (JSON_EXTRACT(order_json, '$.billingAddressId')<>billing_address_id and JSON_EXTRACT(order_json, '$.shippingAddressId')=shipping_address_id))
    then 
    INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.billingAddressId');
    SET v_billing_address_id = LAST_INSERT_ID();
    update chs_ecom_sales_order_address
set billing_address_id=v_billing_address_id where order_id=v_order_id;
  
  else if exists (select 1 from chs_ecom_sales_order_address where order_id=v_order_id and (JSON_EXTRACT(order_json, '$.billingAddressId')=billing_address_id and JSON_EXTRACT(order_json, '$.shippingAddressId')<>shipping_address_id))
    then 
    INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.shippingAddressId');
    SET v_shipping_address_id = LAST_INSERT_ID();
    update chs_ecom_sales_order_address
set shipping_address_id=v_shipping_address_id where order_id=v_order_id;
end if;
end if;
    end if;
        end if;
        end if;

    update chs_core_marketing_discount_usage set status='APPLIED' where discount_txn_id=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),'');
    
    COMMIT;
    
    SELECT JSON_OBJECT(
        'id', om.id,
        'orderNum', om.order_num,
        'cpgOrderId',om.cpg_order_id,
        'username', om.username,
        'customerId', om.customer_id,
        'orderStatus', om.order_status,
        'totalPrice', om.total_price,
        'totalMrp', om.total_mrp,
        'finalPrice',om.final_price,
        'totalItems', om.total_items,
        'totalQty', om.total_qty,
        'discAmount', om.disc_amount,
        'couponDiscAmount',om.coupon_disc_amount,
        'taxAmount', om.tax_amount,
        'shippingCharge', om.shipping_charge,
        'paymentStatus', om.payment_status,
        'paymentMethod', om.payment_method,
        'billingAddressId', oa.billing_address_id,
        'placedOn',DATE_FORMAT(om.placed_on, '%Y-%m-%dT%H:%i:%s'),
        'orderWeight', om.order_weight,
        'amount',om.amount,
        'orderItems', 
        (SELECT JSON_ARRAYAGG(
            JSON_OBJECT(
                'id', oi.id,
                'orderId', oi.order_id, 
                'productId', oi.product_id, 
                'itemId', oi.item_id, 
                
                'itemTitle',oi.item_title,
                'itemImage',oi.item_image,
                'item_slug',oi.item_slug,
                'batchId', oi.batch_id, 
                'qty',oi.qty,
                'unitPrice', oi.unit_price, 
                
                
				'unit_mrp', oi.unit_mrp,
				'volume_unit_price', oi.volume_unit_price,
				'volume_unit_mrp', oi.volume_unit_mrp,
				'tax_amt', oi.tax_amt,
				'total_mrp', oi.total_mrp,

                
                
                'discAmount', oi.disc_amount, 
                'totalPrice', oi.total_price,
                'returnAllowed',oi.return_allowed
            )
        ) FROM chs_ecom_sales_order_items oi WHERE oi.order_id = om.id)
    ) AS output_json
    FROM chs_ecom_sales_order_master om join chs_ecom_sales_order_address oa on om.id=oa.order_id
	WHERE om.id = v_order_id;

END;


-- deployment: Creating sp_product_item_dd...
CREATE PROCEDURE sp_product_item_dd ()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE v_product_code VARCHAR(100);
    DECLARE v_slug VARCHAR(500);
    DECLARE v_sku VARCHAR(50);
    DECLARE v_gtin VARCHAR(12);
    DECLARE v_title VARCHAR(100);
    DECLARE v_description VARCHAR(1000);
    DECLARE v_status VARCHAR(100);
    DECLARE v_total_ratings INT;
    DECLARE v_avg_rating DECIMAL(10,2);
    DECLARE v_is_default TINYINT;
    DECLARE v_min_order_qty INT;
    DECLARE v_max_order_qty INT;
    DECLARE v_return_allowed TINYINT;
    DECLARE v_min_stock_alert TINYINT;
    DECLARE v_available_stock INT;
    DECLARE v_created_by VARCHAR(50) DEFAULT 'system';
    DECLARE v_modified_by VARCHAR(50) DEFAULT 'system';
    DECLARE v_product_id BIGINT;
	DECLARE is_success INT DEFAULT 0;
    DECLARE insert_count INT DEFAULT 0;


    DECLARE cur CURSOR FOR
        SELECT product_code, slug, sku, gtin, title, description, status, total_ratings, avg_rating, is_default, min_order_qty, max_order_qty, return_allowed, min_stock_alert, available_stock
        FROM dd_product_item
        WHERE is_verified = 1;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done=1;
			DECLARE EXIT HANDLER FOR SQLEXCEPTION
				BEGIN
					ROLLBACK;
					-- SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'An error occurred during the transaction. All executed statements have been rolled back.';
					 SET @msg='ALL EXECUTED STATEMENTS ARE ROLLBACKED FOR GETTING ERROR';
					 SET is_success = 0;
				END;

    START TRANSACTION;

    OPEN cur;

    read_loop: LOOP

        FETCH cur INTO v_product_code, v_slug, v_sku, v_gtin, v_title, v_description, v_status, v_total_ratings, v_avg_rating, v_is_default, v_min_order_qty, v_max_order_qty, v_return_allowed, v_min_stock_alert, v_available_stock;

       IF done THEN
            LEAVE read_loop;
        END IF;

        SELECT id INTO v_product_id FROM chs_ecom_pms_product_master WHERE code = v_product_code LIMIT 1;
        -- IF v_product_id IS NOT NULL THEN
        IF v_product_id IS NULL THEN
			SIGNAL SQLSTATE '45000' ;
            SET @msg =  CONCAT('Product code not found: ', v_product_code);
		END IF;
        
            INSERT INTO product_item (
                product_id, slug, sku, gtin, title, description, status, total_ratings, avg_rating, is_default, min_order_qty, max_order_qty, return_allowed, min_stock_alert, available_stock
            ) VALUES (
                v_product_id, v_slug, v_sku, v_gtin, v_title, v_description, v_status, v_total_ratings, v_avg_rating, v_is_default, v_min_order_qty, v_max_order_qty, v_return_allowed, v_min_stock_alert, v_available_stock
            );
		SET insert_count = insert_count + 1;
            /*
            ON DUPLICATE KEY UPDATE
                slug = VALUES(slug),
                title = VALUES(title),
                description = VALUES(description),
                status = VALUES(status),
                total_ratings = VALUES(total_ratings),
                avg_rating = VALUES(avg_rating),
                is_default = VALUES(is_default),
                min_order_qty = VALUES(min_order_qty),
                max_order_qty = VALUES(max_order_qty),
                return_allowed = VALUES(return_allowed),
                min_stock_alert = VALUES(min_stock_alert),
                available_stock = VALUES(available_stock);
                */
       -- END IF;
    END LOOP;
    CLOSE cur;
    IF insert_count > 0 THEN
    COMMIT;
    SET is_success = 1;
    SET @msg = CONCAT('Success: ', insert_count, ' records inserted and deleted.');
    DELETE FROM dd_product_item WHERE is_verified = 1;
ELSE
    ROLLBACK;
    SET is_success = 0;
    SET @msg = 'No inserts performed. Transaction rolled back.';
END IF;
    SELECT is_success AS is_success;
END;


-- deployment: Creating sp_order_search...
CREATE PROCEDURE sp_order_search (IN p_search_key varchar(50), IN p_username varchar(50))
BEGIN 

	DECLARE v_search_key VARCHAR(100);
    DECLARE v_username VARCHAR(50);
    DECLARE v_item_ids text;
    declare v_order_ids text;

    SET v_username = p_username;
	-- SET v_search_key = REPLACE(TRIM(BOTH ' ' FROM REGEXP_REPLACE(LOWER(p_search_key), '[^a-z0-9 ]', '')), ' ', '* +');
	-- SET v_search_key = CONCAT('+', p_search_key, '*');
    
   -- SET v_search_key = REPLACE(TRIM(BOTH ' ' FROM REGEXP_REPLACE(LOWER(p_search_key), '[^a-z0-9 ]', '')), ' ', '* +');
   --  SET v_search_key = CONCAT('+', upper(v_search_key), '*');
     
    SET v_search_key = REPLACE(TRIM(BOTH ' ' FROM REGEXP_REPLACE(LOWER(p_search_key), '[^a-z0-9 ]', '')), ' ', '* ');
	 SET v_search_key = CONCAT( v_search_key, ' *');
	 
   
        
SELECT GROUP_CONCAT(distinct p1.item_id) into v_item_ids
    FROM chs_ecom_pms_product_card p1
    JOIN (
    SELECT DISTINCT p.item_id
    FROM chs_ecom_pms_product_card p
   -- LEFT JOIN cat_prod_map cp ON p.product_id = cp.product_id
  --  LEFT JOIN category c ON cp.category_id = c.id
  --  LEFT JOIN section s ON c.section_id = s.id
    left join chs_ecom_pms_search_keywords sk  on sk.item_id=p.item_id
    WHERE -- p.is_default_item = 1 AND
    p.product_status = 'ACTIVE' AND p.item_status = 'ACTIVE'
    AND p.is_default_img = 1
        AND (
            MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE) OR 
            MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE)
			OR MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE)
           -- OR MATCH(c.title, c.slug) AGAINST(v_search_key IN BOOLEAN MODE)
           -- OR MATCH(s.title, s.slug) AGAINST(v_search_key IN BOOLEAN MODE)
        )
    ORDER BY 
        MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
        MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
        MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE) desc,
      --  MATCH(c.title, c.slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
      --  MATCH(s.title, s.slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
        p.item_title
)AS distinct_products ON p1.item_id = distinct_products.item_id WHERE
    p1.product_status = 'ACTIVE' AND p1.item_status = 'ACTIVE';
    -- AND p1.is_default_img = 1;
    
  --  select v_item_ids;
    
select GROUP_CONCAT(distinct om.id) into v_order_ids from chs_ecom_sales_order_master om where 
 (MATCH(om.order_num) AGAINST(v_search_key IN BOOLEAN MODE) OR om.order_num LIKE CONCAT('%', p_search_key)) and 
om.username = v_username;

SELECT JSON_ARRAYAGG(JSON_OBJECT(
        'id', om.id,
        'orderNum', om.order_num,
        'cpgOrderId',om.cpg_order_id,
        'username', om.username,
        'customerId', om.customer_id,
        'orderStatus', om.order_status,
        'totalPrice', om.total_price,
        'totalMrp', om.total_mrp,
        'finalPrice',om.final_price,
        'totalItems', om.total_items,
        'totalQty', om.total_qty,
        'discAmount', om.disc_amount,
        'couponDiscAmount',om.coupon_disc_amount,
        'taxAmount', om.tax_amount,
        'shippingCharge', om.shipping_charge,
        'paymentStatus', om.payment_status,
        'paymentMethod', om.payment_method,
        'billingAddressId', null,
        'placedOn',DATE_FORMAT(om.placed_on, '%Y-%m-%dT%H:%i:%s'),
        'fileId', om.file_id,
		'invoiceUrl', om.invoice_url,
		'amount', om.amount,
        'walletAmount', om.wallet_amount,
        'orderItems',  (
                SELECT JSON_ARRAYAGG(
                    JSON_OBJECT(
                        'id', oi.id,
						'orderId', oi.order_id, 
                        'productId', oi.product_id,
                        'itemId', oi.item_id,
                        'itemTitle', oi.item_title,
                        'itemImage', oi.item_image,
                        'itemSlug', oi.item_slug,
                        'unitPrice', oi.unit_price,
                        'unitMrp', oi.unit_mrp,
                        'volumeUnitPrice', oi.volume_unit_price,
                        'volumeUnitMrp', oi.volume_unit_mrp,
                        'volumeValue', oi.volume_value,
                        'qty', oi.qty,
                        'taxAmt', oi.tax_amt,
                        'discAmount', oi.disc_amount,
                        'totalPrice', oi.total_price,
                        'totalMrp', oi.total_mrp,
                        'returnAllowed', oi.return_allowed
                    )
                ) FROM chs_ecom_sales_order_items oi WHERE oi.order_id = om.id 
           AND (FIND_IN_SET(oi.item_id, v_item_ids)  OR FIND_IN_SET(oi.order_id, v_order_ids) )
        )
    )
) AS output_json
FROM chs_ecom_sales_order_master om WHERE om.username = v_username
  AND EXISTS (SELECT 1 FROM chs_ecom_sales_order_items oi WHERE oi.order_id = om.id 
      AND (FIND_IN_SET(oi.item_id, v_item_ids)  OR FIND_IN_SET(oi.order_id, v_order_ids) 
  ))
ORDER BY om.placed_on DESC;
  end;


-- deployment: Creating sp_mega_search...
CREATE PROCEDURE sp_mega_search (IN p_search_request json)
BEGIN 

	DECLARE v_search_key VARCHAR(100);
    DECLARE v_min_price FLOAT;
    DECLARE v_max_price FLOAT;
    DECLARE v_category_slugs TEXT;
    DECLARE v_offset int;
    DECLARE v_page_size int;
    DECLARE v_page_offset int;
    DECLARE v_row_count int;
    DECLARE v_min float;
    DECLARE v_max float;

    SET v_min_price =NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.minPrice')),'null'),'');
    SET v_max_price = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.maxPrice')),'null'),'');
	
    
SET v_search_key = CONCAT('+',REPLACE(REGEXP_REPLACE(REPLACE(
        LOWER(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.searchKey')), 'null'), '')),
        '-', ' '),'\\s+', ' '),' ', '* +'),'*');
    
    /* SET v_search_key = REPLACE(TRIM(BOTH ' ' FROM REGEXP_REPLACE(
  LOWER(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.searchKey')), 'null'), '')),
   '[^a-z0-9 _\\.&]','')), '-', ' '); -- convert dash to space
SET v_search_key = REPLACE(v_search_key, ' ', '* +'); 

	 SET v_search_key = CONCAT('+', v_search_key, '*'); */
  -- select v_search_key;
    
    -- SET v_search_key = REPLACE(TRIM(BOTH ' ' FROM REGEXP_REPLACE(
    -- LOWER(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.searchKey')),'null'),'')), '[^a-z0-9 _\-\.&]', '')), ' ', '* +');

	--  SET v_search_key = CONCAT('%', REGEXP_REPLACE(lower(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.searchKey')),'null'),'')), '[^a-zA-Z0-9]', ''), '%');

    
    SET v_category_slugs = (SELECT GROUP_CONCAT(CONCAT( JSON_UNQUOTE(value))) FROM JSON_TABLE(JSON_EXTRACT(p_search_request, '$.categorySlugs'), '$[*]'COLUMNS(value VARCHAR(255) PATH '$')) AS jt);
    
	-- SET v_category_slugs = (SELECT GROUP_CONCAT(JSON_UNQUOTE(value))FROM JSON_TABLE(JSON_EXTRACT(p_search_request, '$.categorySlugs'),'$[*]' COLUMNS(value VARCHAR(255) PATH '$')) AS jt);
    SET v_offset = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.offset')),'null'),'');
    SET v_page_size = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.pageSize')),'null'),'');
	SET v_page_offset = v_offset * v_page_size;

    
IF v_search_key IS NOT NULL THEN
SELECT
 count(DISTINCT p.product_id),min(p.item_price),max(p.item_price) into v_row_count,v_min,v_max
 from( select p.product_id, p.item_price
FROM chs_ecom_pms_product_card p
LEFT JOIN chs_ecom_pms_cat_prod_map cp ON p.product_id = cp.product_id
LEFT JOIN chs_ecom_pms_category c ON cp.category_id = c.id
LEFT JOIN chs_ecom_pms_section s ON c.section_id = s.id
left join chs_ecom_pms_search_keywords sk on sk.product_id = p.product_id
WHERE p.is_default_item = 1 AND
    p.product_status = 'ACTIVE' AND p.item_status = 'ACTIVE'
    AND p.is_default_img = 1
 -- AND ifnull((c.slug in (v_category_slugs)),p.product_id)
	    AND FIND_IN_SET(c.slug, ifnull(v_category_slugs,c.slug))

  AND p.item_price BETWEEN IFNULL(v_min_price, (SELECT MIN(price) FROM chs_ecom_ims_sku_pricing))
                        AND IFNULL(v_max_price, (SELECT MAX(price) FROM chs_ecom_ims_sku_pricing))
  AND (
     MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE)
    OR MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE)
    OR MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE)
    -- OR MATCH(c.title, c.slug) AGAINST(v_search_key IN BOOLEAN MODE)
    -- OR MATCH(s.title, s.slug) AGAINST(v_search_key IN BOOLEAN MODE)
  )
  GROUP BY p.product_id, p.item_price
ORDER BY 
  MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
  MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
  MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE) desc) as p;
  -- MATCH(c.title, c.slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
 -- MATCH(s.title, s.slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,p.product_title ;

SELECT
    JSON_OBJECT(
        'totalRecords', v_row_count,
        'minPrice',v_min,
        'maxPrice',v_max,
        'productCards', JSON_ARRAYAGG(
            JSON_OBJECT(
                'productId', p.product_id,
                'productCode', p.product_code,
                'productTitle', p.product_title,
                'productSlug', p.product_slug,
                'itemId', p.item_id,
                'itemSlug', p.item_slug,
                'itemTitle', p.item_title,
                'itemMrp', p.item_mrp,
                'itemPrice', p.item_price,
                'itemDiscount', p.item_discount,
                'itemImage', p.item_image,
                'currency', p.currency,
                'minQty', p.min_qty,
                'maxQty', p.max_qty,
                'productStatus', p.product_status,
                'itemStatus', p.item_status,
                'isDefaultItem', p.is_default_item,
                'isDefaultImg', p.is_default_img
            )
        ),
        'categories', (
            SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'id',category_id,
        'slug',category_slug,
        'title',category_title,
        'productCount', product_count
    )
) AS chs_ecom_pms_categoryData FROM (
    SELECT 
    default_items.category_id,
    default_items.category_slug,
    default_items.category_title,
    COUNT(DISTINCT default_items.product_slug) AS product_count
FROM
    (select `c`.`id` AS `category_id`,`c`.`slug` AS `category_slug`,`c`.`title` AS `category_title`,`c`.`file_id` AS `file_id`,`c`.`image_url` AS `image_url`,`c`.`status` AS `category_status`,`p`.`product_id` AS `product_id`,`p`.`item_id` AS `item_id`,`s`.`id` AS `section_id`,`p`.`product_title` AS `product_title`,`p`.`item_title` AS `item_title`,`p`.`product_slug` AS `product_slug`,`p`.`item_slug` AS `item_slug`,`s`.`slug` AS `section_slug`,`p`.`is_default_item` AS `is_default_item`,1 AS `product_count` 
from (((`chs_ecom_pms_product_card` `p` left join `chs_ecom_pms_cat_prod_map` `cp` on((`p`.`product_id` = `cp`.`product_id`))) 
left join `chs_ecom_pms_category` `c` on((`cp`.`category_id` = `c`.`id`))) 
left join `chs_ecom_pms_section` `s` on((`c`.`section_id` = `s`.`id`))) 
where ((`p`.`product_status` = 'ACTIVE') and (`p`.`item_status` = 'ACTIVE') and (`p`.`is_default_img` = 1) and (`c`.`status` = 'ACTIVE')) 
order by `c`.`title`) default_items
JOIN (
    SELECT DISTINCT product_slug
    FROM (select `c`.`id` AS `category_id`,`c`.`slug` AS `category_slug`,`c`.`title` AS `category_title`,`c`.`file_id` AS `file_id`,`c`.`image_url` AS `image_url`,`c`.`status` AS `category_status`,`p`.`product_id` AS `product_id`,`p`.`item_id` AS `item_id`,`s`.`id` AS `section_id`,`p`.`product_title` AS `product_title`,`p`.`item_title` AS `item_title`,`p`.`product_slug` AS `product_slug`,`p`.`item_slug` AS `item_slug`,`s`.`slug` AS `section_slug`,`p`.`is_default_item` AS `is_default_item`,1 AS `product_count` 
from (((`chs_ecom_pms_product_card` `p` left join `chs_ecom_pms_cat_prod_map` `cp` on((`p`.`product_id` = `cp`.`product_id`))) 
left join `chs_ecom_pms_category` `c` on((`cp`.`category_id` = `c`.`id`))) 
left join `chs_ecom_pms_section` `s` on((`c`.`section_id` = `s`.`id`))) 
where ((`p`.`product_status` = 'ACTIVE') and (`p`.`item_status` = 'ACTIVE') and (`p`.`is_default_img` = 1) and (`c`.`status` = 'ACTIVE')) 
order by `c`.`title`) cpc
    left join chs_ecom_pms_search_keywords sk on sk.product_id = cpc.product_id
    WHERE
        MATCH(item_title, item_slug) AGAINST(v_search_key IN BOOLEAN MODE)
        OR MATCH(product_title, product_slug) AGAINST(v_search_key IN BOOLEAN MODE)
        OR MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE)
) matched_products ON matched_products.product_slug = default_items.product_slug
WHERE
    default_items.is_default_item = 1
GROUP BY
    default_items.category_id,
    default_items.category_slug,
    default_items.category_title
) AS aggregated_data
        )
    ) AS result
FROM (SELECT distinct p1.*
    FROM chs_ecom_pms_product_card p1
    JOIN (
    SELECT DISTINCT p.product_id
    FROM chs_ecom_pms_product_card p
    LEFT JOIN chs_ecom_pms_cat_prod_map cp ON p.product_id = cp.product_id
    LEFT JOIN chs_ecom_pms_category c ON cp.category_id = c.id
    LEFT JOIN chs_ecom_pms_section s ON c.section_id = s.id
    left join chs_ecom_pms_search_keywords sk on sk.product_id = p.product_id
    WHERE -- p.is_default_item = 1 AND
    p.product_status = 'ACTIVE' AND p.item_status = 'ACTIVE'
    AND p.is_default_img = 1
       -- AND IFNULL((c.slug IN (v_category_slugs)), p.product_id)
               	    AND FIND_IN_SET(c.slug, ifnull(v_category_slugs,c.slug))
		AND p.item_price BETWEEN IFNULL(v_min_price, (SELECT MIN(price) FROM chs_ecom_ims_sku_pricing))
                            AND IFNULL(v_max_price, (SELECT MAX(price) FROM chs_ecom_ims_sku_pricing))
        AND (
            MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE)
            OR MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE)
			OR MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE)
           -- OR MATCH(c.title, c.slug) AGAINST(v_search_key IN BOOLEAN MODE)
           -- OR MATCH(s.title, s.slug) AGAINST(v_search_key IN BOOLEAN MODE)
        )
    ORDER BY 
        MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
        MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
		MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE) desc,
      --  MATCH(c.title, c.slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
      --  MATCH(s.title, s.slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
        p.product_title
    LIMIT v_page_size OFFSET v_page_offset
) AS distinct_products ON p1.product_id = distinct_products.product_id WHERE p1.is_default_item = 1 AND
    p1.product_status = 'ACTIVE' AND p1.item_status = 'ACTIVE'
    AND p1.is_default_img = 1) AS p;
-- actual else
else 

SELECT 
 count(distinct p.product_id),min(p.item_price),max(p.item_price) 
into v_row_count,v_min,v_max
    FROM chs_ecom_pms_product_card p
    LEFT JOIN chs_ecom_pms_cat_prod_map cp ON p.product_id = cp.product_id
    LEFT JOIN chs_ecom_pms_category c ON cp.category_id = c.id
    LEFT JOIN chs_ecom_pms_section s ON c.section_id = s.id
    WHERE is_default_item = 1 AND product_status = 'ACTIVE' AND item_status = 'ACTIVE' AND is_default_img = 1
		AND FIND_IN_SET(c.slug, ifnull(v_category_slugs,c.slug))
        AND p.item_price BETWEEN IFNULL(v_min_price, (SELECT MIN(price) FROM chs_ecom_ims_sku_pricing))
                            AND IFNULL(v_max_price, (SELECT MAX(price) FROM chs_ecom_ims_sku_pricing))
    ORDER BY p.product_title
    LIMIT v_page_size OFFSET v_page_offset;
SELECT
    JSON_OBJECT(
        'totalRecords', v_row_count,
        'minPrice',v_min,
        'maxPrice',v_max,
        'productCards', JSON_ARRAYAGG(
            JSON_OBJECT(
                'productId', p.product_id,
                'productCode', p.product_code,
                'productTitle', p.product_title,
                'productSlug', p.product_slug,
                'itemId', p.item_id,
                'itemSlug', p.item_slug,
                'itemTitle', p.item_title,
                'itemMrp', p.item_mrp,
                'itemPrice', p.item_price,
                'itemDiscount', p.item_discount,
                'itemImage', p.item_image,
                'currency', p.currency,
                'minQty', p.min_qty,
                'maxQty', p.max_qty,
                'productStatus', p.product_status,
                'itemStatus', p.item_status,
                'isDefaultItem', p.is_default_item,
                'isDefaultImg', p.is_default_img
            )
        ),
        'categories', (
            SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'id',category_id,
        'slug', category_slug,
        'title', category_title,
        'productCount', product_count
    )
) AS chs_ecom_pms_categoryData FROM (
    SELECT 
        c2.category_id as category_id,c2.category_slug as category_slug,c2.category_title as category_title,SUM(c2.product_count) AS product_count
    FROM (select `c`.`id` AS `category_id`,`c`.`slug` AS `category_slug`,`c`.`title` AS `category_title`,`c`.`file_id` AS `file_id`,`c`.`image_url` AS `image_url`,`c`.`status` AS `category_status`,`p`.`product_id` AS `product_id`,`p`.`item_id` AS `item_id`,`s`.`id` AS `section_id`,`p`.`product_title` AS `product_title`,`p`.`item_title` AS `item_title`,`p`.`product_slug` AS `product_slug`,`p`.`item_slug` AS `item_slug`,`s`.`slug` AS `section_slug`,`p`.`is_default_item` AS `is_default_item`,1 AS `product_count` 
from (((`chs_ecom_pms_product_card` `p` left join `chs_ecom_pms_cat_prod_map` `cp` on((`p`.`product_id` = `cp`.`product_id`))) 
left join `chs_ecom_pms_category` `c` on((`cp`.`category_id` = `c`.`id`))) 
left join `chs_ecom_pms_section` `s` on((`c`.`section_id` = `s`.`id`))) 
where ((`p`.`product_status` = 'ACTIVE') and (`p`.`item_status` = 'ACTIVE') and (`p`.`is_default_img` = 1) and (`c`.`status` = 'ACTIVE')) 
order by `c`.`title`) c2
    GROUP BY c2.category_id, c2.category_slug, c2.category_title
) AS aggregated_data
        )
    ) AS result
FROM (
    SELECT DISTINCT p.*
    FROM chs_ecom_pms_product_card p
    LEFT JOIN chs_ecom_pms_cat_prod_map cp ON p.product_id = cp.product_id
    LEFT JOIN chs_ecom_pms_category c ON cp.category_id = c.id
    LEFT JOIN chs_ecom_pms_section s ON c.section_id = s.id
    WHERE -- is_default_item = 1 AND 
    product_status = 'ACTIVE' AND item_status = 'ACTIVE' AND is_default_img = 1
	    AND FIND_IN_SET(c.slug, ifnull(v_category_slugs,c.slug))
        AND p.item_price BETWEEN IFNULL(v_min_price, (SELECT MIN(price) FROM chs_ecom_ims_sku_pricing))
                            AND IFNULL(v_max_price, (SELECT MAX(price) FROM chs_ecom_ims_sku_pricing))
    ORDER BY p.product_title
    LIMIT v_page_size OFFSET v_page_offset
) AS p;

end if;

  end;


-- deployment: Creating sp_item_details...
CREATE PROCEDURE sp_item_details (IN p_item_slug varchar(500), IN p_inventory_model varchar(50))
BEGIN
    SELECT JSON_OBJECT(

        'productCard', (
    SELECT JSON_OBJECT(
        'id', pc.id,
        'productId', pc.product_id,
        'productCode', pc.product_code,
        'productSlug', pc.product_slug,
        'productTitle', pc.product_title,

        'itemId', pc.item_id,
        'itemSlug', pc.item_slug,
        'skuCode', pc.sku_code,
        'itemTitle', pc.item_title,

        'itemMrp', pc.item_mrp,
        'itemPrice', pc.item_price,
        'itemDiscount', pc.item_discount,
        'currency', pc.currency,

        'itemImage', pc.item_image,
        'itemImgList', pc.item_imgs,
		'minQty', pc.min_qty,
        'maxQty', pc.max_qty,

        'productStatus', pc.product_status,
        'itemStatus', pc.item_status,

        'isDefaultItem', pc.is_default_item,
        'isDefaultImage', pc.is_default_img,

        'returnAllowed', pc.return_allowed,
        'minStockAlert', pc.min_stock_alert,
        'availableStock', pc.available_stock,
		'exchangeAllowed', pc.exchange_allowed,
        'inventoryModel', pc.inventory_model,
        'description',pi.description,
        'gtin',pi.gtin,
        'isVolumeEnabled',sm.is_volume_enabled,
        'volumeTitle',sm.volume_title,
        'subscriptionEnabled',pc.subscription_enabled,
		'subscriptionPrice',pc.subscription_price

    )
    FROM chs_ecom_pms_product_card pc
    join chs_ecom_ims_sku_master sm on sm.sku_code=pc.sku_code
    WHERE pc.item_id = pi.id
      AND pc.inventory_model = p_inventory_model and is_default_img=1
),

        'ingredients',(
			 SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
					'id',i.id,
                    'title', i.title,
                    'description', i.description,
                    'fileId',i.file_id,
                    'imageUrl',i.image_url
                )
            )
            FROM chs_ecom_pms_product_ingredients pin join chs_ecom_pms_ingredient i on pin.ingredient_id = i.id
            WHERE pin.product_id = pm.id
            ),
     /*   'productData', (
            SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
					'id',ds.id,
                    'productId',ds.product_id,
                    'title', ds.title,
                    'description', ds.description
                )
            )
            FROM chs_ecom_pms_data_section ds
            WHERE ds.product_id = pm.id
        ), */
		'variants', COALESCE((
            SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
                    'id', pv.id,
                    'specDefId', pv.spec_def_id,
                    'productId', pv.product_id,
                    'keyName', psd.spec_key,
                    'variantSpecValues', (
                        SELECT COALESCE(
                            JSON_ARRAYAGG(
                                JSON_OBJECT(
									'itemId',ispec.item_id,
                                    'productSpecId', ispec.product_spec_id,
                                    'keyName', ispec.key_name,
                                    'keyValue', ispec.key_value
                                )
                            ), 
                            JSON_ARRAY()
                        )
                        FROM chs_ecom_pms_item_specs ispec
                        WHERE ispec.product_spec_id = pv.spec_def_id
                          AND ispec.product_id = pv.product_id
                    )
                )
            )
            FROM chs_ecom_pms_product_variant_params pv
            INNER JOIN chs_ecom_pms_product_spec_definition psd 
                ON pv.spec_def_id = psd.id
            WHERE pv.product_id = pi.product_id
        ), JSON_ARRAY()),
        'itemSpecs', (
            SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
					'id',ispec.id, 
                    'itemId',ispec.item_id, 
					'productId',ispec.product_id, 
					'productSpecId' ,ispec.product_spec_id,
                    'keyName', ispec.key_name,
                    'keyValue', ispec.key_value
                )
            )
            FROM chs_ecom_pms_item_specs ispec
            WHERE ispec.item_id = pi.id
        ),
        'relatedProducts', (
        SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
					'id', pc.id,
        'productId', pc.product_id,
        'productCode', pc.product_code,
        'productSlug', pc.product_slug,
        'productTitle', pc.product_title,

        'itemId', pc.item_id,
        'itemSlug', pc.item_slug,
        'skuCode', pc.sku_code,
        'itemTitle', pc.item_title,

        'itemMrp', pc.item_mrp,
        'itemPrice', pc.item_price,
        'itemDiscount', pc.item_discount,
        'currency', pc.currency,

        'itemImage', pc.item_image,
        'itemImgList', pc.item_imgs,
		'minQty', pc.min_qty,
        'maxQty', pc.max_qty,

        'productStatus', pc.product_status,
        'itemStatus', pc.item_status,

        'isDefaultItem', pc.is_default_item,
        'isDefaultImage', pc.is_default_img,

        'returnAllowed', pc.return_allowed,
        'minStockAlert', pc.min_stock_alert,
        'availableStock', pc.available_stock,

        'inventoryModel', pc.inventory_model

                )
            )
            FROM chs_ecom_pms_related_products rp
            join chs_ecom_pms_product_card pc on pc.item_slug=rp.related_item_slug
            WHERE rp.item_slug = pi.slug and pc.inventory_model = p_inventory_model and pc.is_default_img=1
        ),
        
        'comboProducts',(
        SELECT JSON_ARRAYAGG(
            JSON_OBJECT(
                'id', pc.id,
        'productId', pc.product_id,
        'productCode', pc.product_code,
        'productSlug', pc.product_slug,
        'productTitle', pc.product_title,

        'itemId', pc.item_id,
        'itemSlug', pc.item_slug,
        'skuCode', pc.sku_code,
        'itemTitle', pc.item_title,

        'itemMrp', pc.item_mrp,
        'itemPrice', pc.item_price,
        'itemDiscount', pc.item_discount,
        'currency', pc.currency,

        'itemImage', pc.item_image,
        'itemImgList', pc.item_imgs,
		'minQty', pc.min_qty,
        'maxQty', pc.max_qty,

        'productStatus', pc.product_status,
        'itemStatus', pc.item_status,

        'isDefaultItem', pc.is_default_item,
        'isDefaultImage', pc.is_default_img,

        'returnAllowed', pc.return_allowed,
        'minStockAlert', pc.min_stock_alert,
        'availableStock', pc.available_stock,

        'inventoryModel', pc.inventory_model

            )
        )
        FROM chs_ecom_ims_combo_sku cs
        JOIN chs_ecom_ims_sku_master csm1 ON csm1.id = cs.combo_sku_id
        JOIN chs_ecom_ims_sku_master csm2 ON csm2.id = cs.child_sku_id
		join chs_ecom_pms_product_card pc on pc.sku_code=csm2.sku_code
        WHERE cs.combo_sku_id = csm1.id and csm1.sku_code=pi.sku_code and csm1.sku_type = 'COMBO' 
        and pc.inventory_model = p_inventory_model and pc.is_default_img=1
    ),
'complementaryProducts',
(
    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'id', pc.id,
        'productId', pc.product_id,
        'productCode', pc.product_code,
        'productSlug', pc.product_slug,
        'productTitle', pc.product_title,

        'itemId', pc.item_id,
        'itemSlug', pc.item_slug,
        'skuCode', pc.sku_code,
        'itemTitle', pc.item_title,

        'itemMrp', pc.item_mrp,
        'itemPrice', pc.item_price,
        'itemDiscount', pc.item_discount,
        'currency', pc.currency,

        'itemImage', pc.item_image,
        'itemImgList', pc.item_imgs,
        'minQty', pc.min_qty,
        'maxQty', pc.max_qty,

        'productStatus', pc.product_status,
        'itemStatus', pc.item_status,

        'isDefaultItem', pc.is_default_item,
        'isDefaultImage', pc.is_default_img,

        'returnAllowed', pc.return_allowed,
        'minStockAlert', pc.min_stock_alert,
        'availableStock', pc.available_stock,

        'inventoryModel', pc.inventory_model

        )
    )
   FROM chs_ecom_ims_complementary_sku cs
        JOIN chs_ecom_ims_sku_master csm1 ON csm1.id = cs.primary_sku_id
        JOIN chs_ecom_ims_sku_master csm2 ON csm2.id = cs.complimentary_sku_id
		join chs_ecom_pms_product_card pc on pc.sku_code=csm2.sku_code
        WHERE cs.primary_sku_id = csm1.id and csm1.sku_code=pi.sku_code
        and pc.inventory_model = p_inventory_model and pc.is_default_img=1
),
'productVolumes',
(
    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'id', sv.id,
            'skuId',sv.sku_id,
            'volume', sv.volume
        )
    )
    FROM chs_ecom_ims_sku_volume sv
        JOIN chs_ecom_ims_sku_master csm 
        ON csm.id = sv.sku_id
    WHERE sv.sku_id = csm.id and csm.sku_code=pi.sku_code and csm.is_volume_enabled=1
),

   /*     'itemGallery', (
            SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
					'id',ig.id,
                    'itemId',ig.item_id,
                    'fileId',ig.file_id,
                    'fileUrl', ig.file_url,
                    'isDefault', ig.is_default
                )
            )
            FROM chs_ecom_pms_item_gallery ig
            WHERE ig.item_id = pi.id 
        ), */
        'productReviews', (
    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'id', pr.id,
            'productId', pr.product_id,
            'productTitle', pr.product_title,
			'productImg', pr.product_img,
            'displayName',pr.display_name,
            'username', pr.username,
            'title', pr.title,
            'description', pr.description,
            'rating', pr.rating,
            'generatedOn', DATE_FORMAT(pr.generated_on, '%Y-%m-%dT%H:%i:%s'),
            'displayable',displayable,
            'productReviewGalleryList', (
                SELECT JSON_ARRAYAGG(
                    JSON_OBJECT(
                        'id', prg.id,
                        'productId', prg.product_id,
