    )
    FROM chs_ecom_pms_product_reviews pr
    WHERE pr.product_id = pm.id and displayable=1
)
    ) AS itemDetails
    FROM chs_ecom_pms_product_item pi
    JOIN chs_ecom_pms_product_master pm ON pm.id = pi.product_id
    WHERE pi.slug = p_item_slug
    LIMIT 1;

END;


-- deployment: Creating sp_get_search_suggestions...
CREATE PROCEDURE sp_get_search_suggestions (IN p_search_key varchar(100))
BEGIN
    DECLARE v_search_key VARCHAR(100);

    SET v_search_key = REPLACE(
        TRIM(BOTH ' ' FROM REGEXP_REPLACE(LOWER(p_search_key), '[^a-z0-9 ]', '')), ' ', '* +');
    SET v_search_key = CONCAT('+', v_search_key, '*');

    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'itemSlug', p.item_slug,
            'itemTitle', p.item_title
        )
    ) AS result
    FROM (
        SELECT DISTINCT p1.item_slug, p1.item_title
        FROM chs_ecom_pms_product_card p1
        JOIN (
            SELECT DISTINCT p.product_id
            FROM chs_ecom_pms_product_card p
            LEFT JOIN chs_ecom_pms_search_keywords sk ON sk.product_id = p.product_id
            WHERE (
                  MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE)
                  OR MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE)
                  OR MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE)
              )
            ORDER BY
                MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
                MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
                MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
                p.product_title
        ) AS distinct_products ON p1.product_id = distinct_products.product_id
    ) AS p;
END;


-- deployment: Creating sp_get_order_summary...
CREATE PROCEDURE sp_get_order_summary (IN orderNum varchar(50))
BEGIN
    DECLARE order_json JSON;
    DECLARE product_json JSON;

    SELECT JSON_OBJECT(
        'id', o.id,
        'orderNum', o.order_num,
        'username', o.username,
		'customer',(SELECT (JSON_OBJECT(
					'id', c.id,
					'firstName',c.first_name,
					'middleName',c.middle_name,
					'lastName',c.last_name,
					'username', c.username,
					'gender', c.gender,
					'dob', c.dob,
					'anniversary', c.anniversary,
					'mobileNumber', c.mobile_number,
					'emailId', c.email_id,
					'referredBy', c.referred_by,
					'prefLang', c.pref_lang,
					'registeredOn', DATE_FORMAT(c.registered_on, '%Y-%m-%dT%H:%i:%s'),
					'currency', c.currency
					))),
        'orderStatus', o.order_status,
        'totalMrp', o.total_mrp,
        'finalPrice', o.final_price,
        'couponDiscAmount', o.coupon_disc_amount,
        'totalPrice', o.total_price,
        'discAmount', o.disc_amount,
        'taxAmount', o.tax_amount,
        'shippingCharge', o.shipping_charge,
        'paymentStatus', o.payment_status,
        'paymentMethod', o.payment_method,
        'invoiceUrl', o.invoice_url,
		'placedOn', DATE_FORMAT(o.placed_on, '%Y-%m-%dT%H:%i:%s'),
        'billingAddress',(SELECT (JSON_OBJECT(
            'id', ba.id,
            'fullName', ba.full_name,
            'phoneNumber', ba.phone_number,
            'addressLine1', ba.address_line1,
            'addressLine2', ba.address_line2,
            'city', ba.city,
            'state', ba.state,
            'country', ba.country,
            'postalCode', ba.postal_code
        ))),
        'shippingAddress',(SELECT (JSON_OBJECT(
            'id', sa.id,
            'fullName', sa.full_name,
            'phoneNumber', sa.phone_number,
            'addressLine1', sa.address_line1,
            'addressLine2', sa.address_line2,
            'city', sa.city,
            'state', sa.state,
            'country', sa.country,
            'postalCode', sa.postal_code
        )))
    ) INTO order_json
    FROM chs_ecom_sales_order_master o
    LEFT JOIN chs_ecom_customer_customer c ON o.customer_id=c.id
    JOIN chs_ecom_sales_order_address oa ON oa.order_id=o.id
    LEFT JOIN chs_core_utils_address_master ba ON oa.billing_address_id = ba.id
    LEFT JOIN chs_core_utils_address_master sa ON oa.shipping_address_id = sa.id
    WHERE o.order_num = orderNum;

   SELECT JSON_ARRAYAGG(
    JSON_OBJECT(
        'productId', p.id,
        'productCode', p.code,
        'itemId', i.id,
        'currency',ip.currency,
        'itemStatus',i.status,
        'itemSlug', i.slug,
        'productSlug', p.slug,
		'productStatus', p.status,
        'productTitle', p.title,
        'itemTitle', i.title,
        'itemImage', ig.file_url,
        'itemMrp', ip.item_mrp,
        'itemPrice', ip.item_price,
        'itemDiscount', ip.item_discount,
        'maxQty', i.max_order_qty,
		'minQty', i.min_order_qty,
		'qty', oi.qty

    )
) INTO product_json
FROM chs_ecom_sales_order_items oi
JOIN chs_ecom_sales_order_master o ON o.id=oi.order_id
JOIN chs_ecom_pms_product_item i ON oi.item_id = i.id
JOIN chs_ecom_pms_product_master p ON i.product_id = p.id
JOIN chs_ecom_pms_product_card ip ON i.id = ip.item_id
JOIN chs_ecom_pms_item_gallery ig ON i.id = ig.item_id
WHERE o.order_num = orderNum
  AND ig.is_default = 1;


    SELECT JSON_OBJECT(
        'id',  NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.id')),'null'),''),
        'orderNum',  NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.orderNum')),'null'),''),
        'username',  NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.username')),'null'),''),
		'customer',  NULLIF(NULLIF(CAST(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.customer')) AS JSON),'null'),''),
        'orderStatus',  NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.orderStatus')),'null'),''),
		'totalMrp', JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.totalMrp')),
        'finalPrice', JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.finalPrice')),
        'couponDiscAmount', JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),
        'totalPrice', JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.totalPrice')),
        'discAmount', JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.discAmount')),
        'taxAmount', JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.taxAmount')),
        'shippingCharge', JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.shippingCharge')),
        'paymentStatus',  NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentStatus')),'null'),''),
        'paymentMethod',  NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentMethod')),'null'),''),
		'invoiceUrl', NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.invoiceUrl')),'null'),''), 
        'placedOn', CASE
        WHEN JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.placedOn')) IS NOT NULL 
             AND JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.placedOn')) != ''
             AND JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.placedOn')) != 'null'
        THEN DATE_FORMAT(STR_TO_DATE(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.placedOn')), '%Y-%m-%dT%H:%i:%s'), '%Y-%m-%dT%H:%i:%s')
        ELSE NULL
    END,
		-- 'placedOn', DATE_FORMAT(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.placedOn')),'null'),''), '%Y-%m-%dT%H:%i:%s'),
        'billingAddress',  NULLIF(NULLIF(CAST(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.billingAddress')) AS JSON),'null'),''),
        'shippingAddress', NULLIF(NULLIF( CAST(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.shippingAddress')) AS JSON),'null'),''),
        'productCards', IFNULL(product_json, JSON_ARRAY())
    ) AS result;

END;


-- deployment: Creating sp_get_indent_details...
CREATE PROCEDURE sp_get_indent_details (IN p_indent_id bigint)
BEGIN
    SELECT JSON_OBJECT(
        'id', i.id,
        'sourceWarehouseId', i.source_warehouse_id,
        'sourceData',JSON_OBJECT(
                    'id', wm1.id, 'name', wm1.name, 'code', wm1.code,
                    'status', wm1.status, 'latitude', wm1.latitude, 'longitude', wm1.longitude
                ),
        'destinationId', i.destination_warehouse_id,
        'destinationData',JSON_OBJECT(
                    'id', wm2.id, 'name', wm2.name, 'code', wm2.code,
                    'status', wm2.status, 'latitude', wm2.latitude, 'longitude', wm2.longitude
                ),
        'movementDate', DATE_FORMAT(i.movement_date, '%Y-%m-%dT%H:%i:%s'),
        'notes', i.notes,
        'indentItems', (
            SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
                    'id', ii.id,
                    'indentId', ii.indent_id,
                    'skuCode', ii.sku_code,
                    'skuData', JSON_OBJECT(
    'id', rm.id,
    'skuCode', rm.sku_code,
    'skuName', rm.sku_name,
    'skuType', rm.sku_type,
    'unitOfMeasure', rm.unit_of_measure,
    'isStockable', rm.is_stockable,
    'isSellable', rm.is_sellable,
    'isPurchasable', rm.is_purchasable,
    'isVolumeEnabled', rm.is_volume_enabled,
    'volumeTitle', rm.volume_title,
    'status', rm.status
),
                    'unit', ii.unit,
                    'quantity', ii.quantity,
                    'batchNumber', ii.batch_number
                )
            )
            FROM chs_ecom_wms_indent_items ii
            LEFT JOIN chs_ecom_ims_sku_master rm ON ii.sku_code = rm.sku_code
            WHERE ii.indent_id = i.id
        )
    ) AS indent_json
    FROM chs_ecom_wms_indent i
    LEFT JOIN chs_ecom_wms_warehouse wm1 on i.source_warehouse_id = wm1.id
    LEFT JOIN chs_ecom_wms_warehouse wm2 on i.destination_warehouse_id = wm2.id
    WHERE i.id = p_indent_id;
END;


-- deployment: Creating sp_get_indents...
CREATE PROCEDURE sp_get_indents ()
BEGIN
 SELECT JSON_ARRAYAGG(indent_json) AS all_indents_json
    FROM (
    SELECT JSON_OBJECT(
        'id', i.id,
        'sourceWarehouseId',i.source_warehouse_id,
        'sourceData',JSON_OBJECT(
                    'id', wm1.id, 'name', wm1.name, 'code', wm1.code, 
                    'status', wm1.status, 'latitude', wm1.latitude, 'longitude', wm1.longitude
                ),
        'destinationWarehouseId', i.destination_warehouse_id,
        'destinationData',JSON_OBJECT(
                    'id', wm2.id, 'name', wm2.name, 'code', wm2.code,
                    'status', wm2.status, 'latitude', wm2.latitude, 'longitude', wm2.longitude
                ),
		'movementDate', DATE_FORMAT(i.movement_date, '%Y-%m-%dT%H:%i:%s'),
        'notes', i.notes
    ) AS indent_json
    FROM chs_ecom_wms_indent i
    LEFT JOIN chs_ecom_wms_warehouse wm1 on i.source_warehouse_id = wm1.id
    LEFT JOIN chs_ecom_wms_warehouse wm2 on i.destination_warehouse_id = wm2.id
    ) t;
END;


-- deployment: Creating sp_generate_top_selling_products...
CREATE PROCEDURE sp_generate_top_selling_products (IN p_report_date date)
BEGIN
     DELETE FROM chs_ecom_sales_top_selling_products WHERE report_date = p_report_date;

    INSERT INTO chs_ecom_sales_top_selling_products (
        report_date, generated_on, item_title, item_slug, img_url, item_sku, value_type, value
    )
    SELECT p_report_date, NOW(), pi.title, pi.slug, ig.file_url, pi.sku,
           'REVENUE', SUM(oi.qty * oi.unit_price) AS revenue
    FROM chs_ecom_sales_order_master om
    left JOIN chs_ecom_sales_order_items oi ON om.id = oi.order_id
    right JOIN chs_ecom_pms_product_item pi ON pi.id = oi.item_id
    left join chs_ecom_pms_item_gallery ig on pi.id=ig.item_id
    WHERE DATE(om.placed_on) = p_report_date
     -- AND om.order_status IN ('DELIVERED','COMPLETED') 
      and ig.is_default = 1
    GROUP BY pi.id
    ORDER BY SUM(oi.qty * oi.unit_price) DESC
    LIMIT 10;

    -- Top 10 by quantity
    INSERT INTO chs_ecom_sales_top_selling_products (
        report_date, generated_on, item_title, item_slug, img_url, item_sku, value_type, value
    )
    SELECT p_report_date, NOW(), pi.title, pi.slug, ig.file_url, pi.sku,
           'QUANTITY', SUM(oi.qty) AS qty_sold
    FROM chs_ecom_sales_order_master om
    left JOIN chs_ecom_sales_order_items oi ON om.id = oi.order_id
    right JOIN chs_ecom_pms_product_item pi ON pi.id = oi.item_id
    left join chs_ecom_pms_item_gallery ig on pi.id=ig.item_id
    WHERE DATE(om.placed_on) = p_report_date
     -- AND om.order_status IN ('DELIVERED','COMPLETED')
      and ig.is_default = 1
    GROUP BY pi.id
    ORDER BY qty_sold DESC
    LIMIT 10;
END;


-- deployment: Creating sp_generate_no_sale_products...
CREATE PROCEDURE sp_generate_no_sale_products (IN p_report_date date)
BEGIN
     DELETE FROM chs_ecom_sales_no_sale_products WHERE report_date = p_report_date;

    INSERT INTO chs_ecom_sales_no_sale_products (
        report_date, generated_on, item_title, item_slug, img_url, item_sku
    )
    SELECT p_report_date, NOW(), pi.title, pi.slug, ig.file_url, pi.sku
    FROM chs_ecom_pms_product_item pi
    LEFT JOIN chs_ecom_pms_item_gallery ig ON pi.id = ig.item_id AND ig.is_default = 1 
    WHERE pi.id NOT IN (
        SELECT DISTINCT oi.item_id
        FROM chs_ecom_sales_order_master om
        JOIN chs_ecom_sales_order_items oi ON om.id = oi.order_id
        WHERE DATE(om.placed_on) = p_report_date
        --  AND om.order_status IN ('DELIVERED','COMPLETED')
    ) and pi.status='ACTIVE'
	LIMIT 10;
END;


-- deployment: Creating sp_generate_low_selling_products...
CREATE PROCEDURE sp_generate_low_selling_products (IN p_report_date date)
BEGIN
     DELETE FROM chs_ecom_sales_low_selling_products WHERE report_date = p_report_date;

    INSERT INTO chs_ecom_sales_low_selling_products (report_date, generated_on, item_title, item_slug, img_url, item_sku, value_type, value)
    SELECT p_report_date, NOW(), pi.title, pi.slug, ig.file_url, pi.sku,
           'REVENUE', SUM(oi.qty * oi.unit_price) AS revenue
    FROM chs_ecom_sales_order_master om
    left JOIN chs_ecom_sales_order_items oi ON om.id = oi.order_id
    right JOIN chs_ecom_pms_product_item pi ON pi.id = oi.item_id
    left join chs_ecom_pms_item_gallery ig on pi.id=ig.item_id
    WHERE DATE(om.placed_on) = p_report_date
      -- AND om.order_status IN ('DELIVERED','COMPLETED') 
      and ig.is_default = 1 -- and  SUM(oi.qty * oi.unit_price) is not null
    GROUP BY pi.id 
    ORDER BY SUM(oi.qty * oi.unit_price) ASC
    LIMIT 10;

    -- Bottom 10 by quantity (but sold > 0)
	INSERT INTO chs_ecom_sales_low_selling_products (report_date, generated_on, item_title, item_slug, img_url, item_sku, value_type, value)
    SELECT p_report_date, NOW(), pi.title, pi.slug, ig.file_url, pi.sku,
           'QUANTITY', SUM(oi.qty) AS qty_sold
    FROM chs_ecom_sales_order_master om
    JOIN chs_ecom_sales_order_items oi ON om.id = oi.order_id
    RIGHT JOIN chs_ecom_pms_product_item pi ON pi.id = oi.item_id
    LEFT JOIN chs_ecom_pms_item_gallery ig ON pi.id = ig.item_id AND ig.is_default = 1
    WHERE DATE(om.placed_on) = p_report_date
   --   AND om.order_status IN ('DELIVERED','COMPLETED')
    GROUP BY pi.id
    HAVING qty_sold > 0
    ORDER BY qty_sold ASC
    LIMIT 10;
END;


-- deployment: Creating sp_generate_day_sale_summary...
CREATE PROCEDURE sp_generate_day_sale_summary (IN p_report_date date, IN p_generated_by varchar(50))
BEGIN
    DECLARE v_total_products_sold INT DEFAULT 0;
    DECLARE v_total_sales_value DECIMAL(14,2) DEFAULT 0.00;
    DECLARE v_total_orders INT DEFAULT 0;
    DECLARE v_total_products_count INT DEFAULT 0;
    DECLARE v_total_customers INT DEFAULT 0;
    DECLARE v_total_cart_value DECIMAL(14,2) DEFAULT 0.00;
    DECLARE v_avg_order_value DECIMAL(14,2) DEFAULT 0.00;
    DECLARE v_highest_order_value DECIMAL(14,2) DEFAULT 0.00;
    DECLARE v_lowest_order_value DECIMAL(14,2) DEFAULT 0.00;
    DECLARE v_highest_value_product VARCHAR(50);
    DECLARE v_highest_sale_value_product VARCHAR(50);

    -- Orders & Items
    SELECT 
        IFNULL(SUM(oi.qty),0),
        IFNULL(COUNT(DISTINCT oi.product_id),0)
    INTO v_total_products_sold, v_total_products_count
    FROM chs_ecom_sales_order_master om
    JOIN chs_ecom_sales_order_items oi ON om.id = oi.order_id
    WHERE DATE(om.placed_on) = p_report_date;
     -- AND om.order_status IN ('DELIVERED','COMPLETED');

    SELECT 
        IFNULL(SUM(om.final_price),0),
        IFNULL(COUNT(DISTINCT om.id),0),
        IFNULL(COUNT(DISTINCT om.customer_id),0),
        IFNULL(AVG(om.final_price),0),
        IFNULL(MAX(om.final_price),0),
        IFNULL(MIN(om.final_price),0)
    INTO v_total_sales_value,v_total_orders, v_total_customers, v_avg_order_value, v_highest_order_value, v_lowest_order_value
    FROM chs_ecom_sales_order_master om
    WHERE DATE(om.placed_on) = p_report_date;
   --   AND om.order_status IN ('DELIVERED','COMPLETED');

    SELECT IFNULL(SUM(total_price),0)
    INTO v_total_cart_value
    FROM chs_ecom_sales_cart
    WHERE DATE(last_modified_on) = p_report_date;

    SELECT pi.title
    INTO v_highest_value_product
    FROM chs_ecom_sales_order_items oi
    JOIN chs_ecom_sales_order_master om ON om.id = oi.order_id
    left join chs_ecom_pms_product_item pi on oi.item_id=pi.id
    WHERE DATE(om.placed_on) = p_report_date
    --  AND om.order_status IN ('DELIVERED','COMPLETED')
    ORDER BY oi.unit_price DESC
    LIMIT 1;

    SELECT title
    INTO v_highest_sale_value_product
    FROM (
        SELECT pi.title,oi.item_id, SUM(oi.qty * oi.unit_price) AS total_sale
        FROM chs_ecom_sales_order_items oi
        JOIN chs_ecom_sales_order_master om ON om.id = oi.order_id
        left join chs_ecom_pms_product_item pi on oi.item_id=pi.id
        WHERE DATE(om.placed_on) = p_report_date
        --  AND om.order_status IN ('DELIVERED','COMPLETED')
        GROUP BY oi.item_id,pi.title
        ORDER BY total_sale DESC
        LIMIT 1
    ) t;

	 DELETE FROM chs_ecom_sales_day_sale_summary WHERE report_date = p_report_date;

    -- Insert into summary
    INSERT INTO chs_ecom_sales_day_sale_summary(
        report_date, generated_on, generated_by,
        total_products_sold, total_sales_value, total_orders, total_products_count,
        total_customers, total_cart_value, avg_order_value, highest_order_value,
        lowest_order_value, highest_value_product, highest_sale_value_product
    ) VALUES (
        p_report_date, NOW(), p_generated_by,
        v_total_products_sold, v_total_sales_value, v_total_orders, v_total_products_count,
        v_total_customers, v_total_cart_value, v_avg_order_value, v_highest_order_value,
        v_lowest_order_value, v_highest_value_product, v_highest_sale_value_product
    );
END;


-- deployment: Creating sp_dispatch_unit_dd...
CREATE PROCEDURE sp_dispatch_unit_dd ()
BEGIN
    DECLARE done INT DEFAULT 0;
    -- Variables for dd_dispatch_unit fields
    DECLARE v_name VARCHAR(100);
    DECLARE v_code VARCHAR(50);
    DECLARE v_email VARCHAR(500);
    DECLARE v_full_name VARCHAR(100);
    DECLARE v_phone_number VARCHAR(20);
    DECLARE v_address_line1 VARCHAR(255);
    DECLARE v_address_line2 VARCHAR(255);
    DECLARE v_city VARCHAR(100);
    DECLARE v_state VARCHAR(100);
    DECLARE v_country VARCHAR(100);
    DECLARE v_postal_code VARCHAR(10);
    DECLARE v_pickup_location_id BIGINT;
    DECLARE v_pickup_location_name VARCHAR(100);
    DECLARE v_status VARCHAR(100);
    DECLARE v_latitude DOUBLE;
    DECLARE v_longitude DOUBLE;
    DECLARE v_is_verified TINYINT;
    -- Variables for target table
    DECLARE v_dispatch_unit_id BIGINT;
    DECLARE v_address_id BIGINT;
    DECLARE is_success INT DEFAULT 0;
    DECLARE insert_count INT DEFAULT 0;

    DECLARE cur CURSOR FOR
        SELECT  name, code, email, full_name, phone_number, address_line1, address_line2, city, state, country, postal_code,
               pickup_location_id, pickup_location_name, status, latitude, longitude, is_verified
        FROM dd_dispatch_unit
        WHERE is_verified = 1;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        SET is_success = 0;
    END;

    START TRANSACTION;

    OPEN cur;

    read_loop: LOOP
        FETCH cur INTO  v_name, v_code, v_email, v_full_name, v_phone_number, v_address_line1, v_address_line2, v_city, v_state, v_country, v_postal_code,
            v_pickup_location_id, v_pickup_location_name, v_status, v_latitude, v_longitude, v_is_verified;
        IF done THEN
            LEAVE read_loop;
        END IF;

       

        -- Check if dispatch_unit with same code exists
        SELECT id INTO v_dispatch_unit_id FROM chs_ecom_wms_dispatch_unit WHERE code = v_code LIMIT 1;

        IF v_dispatch_unit_id IS NULL THEN
         INSERT INTO chs_core_commons_address_master (
            address_line1, address_line2, city, state, country, postal_code
        ) VALUES (
            v_address_line1, v_address_line2, v_city, v_state, v_country, v_postal_code
        );
        SET v_address_id = LAST_INSERT_ID();
        
            INSERT INTO chs_ecom_wms_dispatch_unit (
                name, code, email, address_id, pickup_location_id, pickup_location_name, status,
                latitude, longitude, created_on, created_by, modified_on, modified_by
            )
            VALUES (
                v_name, v_code, v_email, v_address_id, v_pickup_location_id, v_pickup_location_name, v_status,
                v_latitude, v_longitude, NOW(), 'system', NULL, NULL
            );
			SET insert_count = insert_count + 1;

        END IF;
    END LOOP;

    CLOSE cur;
 IF insert_count > 0 THEN
    COMMIT;
    SET is_success = 1;
    SET @msg = CONCAT('Success: ', insert_count, ' records inserted and deleted.');
    DELETE FROM dd_dispatch_unit WHERE is_verified = 1;
ELSE
    ROLLBACK;
    SET is_success = 0;
    SET @msg = 'No inserts performed. Transaction rolled back.';
END IF;


    SELECT is_success AS is_success;
END;


-- deployment: Creating sp_define_product...
CREATE PROCEDURE sp_define_product (IN product_json json)
BEGIN
    DECLARE product_id BIGINT;
    DECLARE item_id BIGINT;
    DECLARE i INT DEFAULT 0;
    DECLARE spec_count INT DEFAULT 0;
    DECLARE variant_param_id BIGINT;
    declare outputJson text;
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        select outputJson;
    END;
    
    START TRANSACTION;
    
    INSERT INTO chs_ecom_pms_product_master (
		def_id,
        slug, 
        code, 
        title, 
        description, 
        status
    ) VALUES (
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.defId')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.slug')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.code')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.title')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.description')),'null'),''),
        'OUT_OF_STOCK'
        -- NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.status')),'null'),'')
    );
    SET product_id = LAST_INSERT_ID();
   
    --    insert into chs_ecom_pms_cat_prod_map(product_id,category_id) values(product_id, NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.categoryId')),'null'),''));
   
    INSERT INTO chs_ecom_pms_product_item (
        product_id,
        slug,
        sku,
        gtin,
        title,
        description,
        status,
        is_default,
        min_order_qty,
        max_order_qty,
        return_allowed
    ) VALUES (
        product_id,
		NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.slug')),'null'),''),
		NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.sku')),'null'),''),
		NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.gtin')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.title')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.description')),'null'),''),
        'OUT_OF_STOCK',
		-- NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.status')),'null'),''),
        IFNULL(IF(LOWER(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.isDefault'))) = 'true', 1, 0),0),
		-- ifnull(if(JSON_EXTRACT(product_json, '$.item.isDefault'),true,1,0),0),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.minOrderQty')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.maxOrderQty')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.returnAllowed')),'null'),'')
    );
    SET item_id = LAST_INSERT_ID();
    INSERT INTO chs_ecom_ims_item_pricing (
        item_id,
        batch_id,
        mrp,
        market_price,
        price,
        discount,
        currency,
        last_updated_on,
        price_changed_on
    ) VALUES (
        item_id,
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.itemPricing.batchId')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.itemPricing.mrp')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.itemPricing.marketPrice')),'null'),''),
		NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.itemPricing.price')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.itemPricing.discount')),'null'),''),
		NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, '$.item.itemPricing.currency')),'null'),''),
        now(),
        now()
    );
    SET i = 0;
    SET spec_count = JSON_LENGTH(product_json, '$.item.itemSpecs');
    WHILE i < spec_count DO
        INSERT INTO chs_ecom_pms_item_specs (
            item_id,
            product_id,
            product_spec_id,
			key_name,
            key_value
        ) VALUES (
            item_id,
            product_id,
			NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, CONCAT('$.item.itemSpecs[', i, '].productSpecId'))),'null'),''),
            NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, CONCAT('$.item.itemSpecs[', i, '].keyName'))),'null'),''),
            NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, CONCAT('$.item.itemSpecs[', i, '].keyValue'))),'null'),'')
        );
        IF JSON_EXTRACT(product_json, CONCAT('$.item.itemSpecs[', i, '].isVariant')) THEN
            INSERT INTO chs_ecom_pms_product_variant_params (product_id, spec_def_id)
            VALUES (product_id,
			NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(product_json, CONCAT('$.item.itemSpecs[', i, '].productSpecId'))),'null'),''));
        END IF;
        SET i = i + 1;
    END WHILE;
    
    INSERT INTO chs_ecom_ims_item_stock (
	item_id, qty, last_modified_on, min_stock_value
    ) VALUES (
        item_id,
        0,
        now(),
        10
    );
    
    COMMIT;
    
 SELECT 
    JSON_OBJECT(
        'id', p.id,
        'defId',p.def_id,
        'slug', p.slug,
        'code', p.code,
        'title', p.title,
        'description', p.description,
        'status', p.status,
        'item', JSON_OBJECT(
            'id', i.id,
            'productId', product_id,
            'slug', i.slug,
            'sku', i.sku,
            'gtin', i.gtin,
            'title', i.title,
            'description', i.description,
            'status', i.status,
            'isDefault', i.is_default,
            'minOrderQty',i.min_order_qty,
            'maxOrderQty',i.max_order_qty,
            'returnAllowed',i.return_allowed,
            'itemPricing', JSON_OBJECT(
				'id', ip.id,
				'itemId', item_id,
				'batchId',ip.batch_Id,
                'mrp', ip.mrp,
                'marketPrice', ip.market_price,
                'price', ip.price,
                'discount', ip.discount,
                'currency', ip.currency,
                'last_updated_on',ip.last_updated_on,
                'priceChangedOn',DATE_FORMAT(ip.price_changed_on, '%Y-%m-%dT%H:%i:%s')
            ),
            'itemSpecs', (
                SELECT JSON_ARRAYAGG(
                    JSON_OBJECT(
						'id',ispec.id,
                        'product_id',ispec.product_id,
                        'itemId',item_id,
                        'productSpecId',ispec.product_spec_id,
                        'keyName', ispec.key_name,
                        'keyValue', ispec.key_value
                    )
                ) 
                FROM chs_ecom_pms_item_specs ispec 
                WHERE ispec.item_id = i.id
            )
        ),
        'productVariantParams', (
            SELECT JSON_ARRAYAGG(
                JSON_OBJECT(
					'id', ps.id,
                    'specDefId', ps.spec_def_id,
                    'productId', product_id
                )
            ) 
            FROM chs_ecom_pms_product_variant_params ps 
            WHERE ps.product_id = p.id
        )
    ) AS outputJson
FROM chs_ecom_pms_product_master p
JOIN chs_ecom_pms_product_item i ON i.product_id = p.id
JOIN chs_ecom_ims_item_pricing ip ON ip.item_id = i.id
WHERE p.id = product_id; 

END;


-- deployment: Creating sp_create_order...
CREATE PROCEDURE sp_create_order (IN order_json json)
BEGIN
    DECLARE v_order_id BIGINT;
    DECLARE i INT DEFAULT 0;
    DECLARE item_count INT DEFAULT 0;
    DECLARE v_shipping_address_id BIGINT DEFAULT NULL;
	DECLARE v_billing_address_id BIGINT DEFAULT NULL;
    DECLARE v_order_num varchar(50);
    DECLARE v_return_order varchar(10);
    DECLARE v_returnable tinyint;
	DECLARE payment_retry INT DEFAULT 0;
    DECLARE current_date_time datetime;
	DECLARE retry_payment_time datetime;
    DECLARE v_total_item_weight DECIMAL(10,2);
    
    DECLARE v_item_id varchar(50);
    DECLARE v_inventory_model varchar(50);
    DECLARE v_wallet_debit_type varchar(100);
    DECLARE v_exchange_allowed tinyint;
    DECLARE v_item_title VARCHAR(255) ;
	DECLARE v_item_image VARCHAR(500);
	DECLARE v_item_slug VARCHAR(255) ;
	DECLARE v_unit_mrp DECIMAL(10,2);
    DECLARE v_unit_price DECIMAL(10,2);
	DECLARE v_tax_amt DECIMAL(10,2);
	DECLARE v_subscription_enabled tinyint;
    
    

    START TRANSACTION;
    set v_order_num=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.orderNum')),'null'),'');
	--  if not exists(select 1 from chs_ecom_sales_order_master where order_num=v_order_num)
    -- actual if start
    if v_order_num is null
    then
    
     SET v_order_num = UPPER(SUBSTRING(UUID(), 1, 6));


   WHILE EXISTS (SELECT 1 FROM chs_ecom_sales_order_master WHERE order_num = v_order_num) DO
   SET v_order_num = UPPER(SUBSTRING(UUID(), 1, 6));END WHILE;

    set v_wallet_debit_type=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletDebitType')),'null'),'');
	SET payment_retry=(SELECT param_value FROM chs_core_settings_code_details WHERE code_id=2 AND param_key="RETRY_PAYMENT_MINUTES");
	SET current_date_time = now();
    SET retry_payment_time = DATE_ADD(current_date_time, INTERVAL payment_retry MINUTE);
    INSERT INTO chs_ecom_sales_order_master(
		order_num, 
        cpg_order_id,
        username, 
        customer_id, 
        order_status,
        total_price,
        total_mrp,
        final_price,
        total_items,
        total_qty,
        disc_amount, 
        coupon_disc_amount,
        tax_amount, 
        shipping_charge, 
        payment_status, 
        payment_method,
        retry_payment_time,
      --  billing_address_id,
        placed_on,
        is_wallet_included, 
		wallet_txn_id,
		wallet_amount, 
		amount,
		wallet_debit_type,
        supply_model
    ) VALUES (
        v_order_num,
        -- concat(SUBSTRING_INDEX(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.username')),'null'),''), '-', -1),DATE_FORMAT(NOW(), '%Y%m%d%H%i%s')),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.cpgOrderId')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.username')),'null'),''),
        (select id from chs_ecom_customer_customer where username=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.username')),'null'),'')),
        CASE WHEN v_wallet_debit_type='FULL' then 'ORDER_PLACED' ELSE 'CREATED' END,
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.totalPrice')),0.0),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.totalMrp')),0.0),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.finalPrice')),0.0),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.totalItems')),0),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.totalQty')),0),''),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.discAmount')),''),0.0),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),''),0.0),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.taxAmount')),''),0.0),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.shippingCharge')),''),0.0),
        CASE WHEN v_wallet_debit_type='FULL' then 'COMPLETED' ELSE 'PENDING' END,
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentMethod')),'null'),''),
      --  NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.billingAddressId')),'null'),''),
        retry_payment_time,
        current_date_time,
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletInclude')),0),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletTxnId')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletAmount')),0.0),''),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.amount')),''),0.0),
        v_wallet_debit_type,
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.supplyModel')),''),0.0)
    );
    
    SET v_order_id = LAST_INSERT_ID();
    
    INSERT INTO chs_ecom_sales_order_workflow
    (
		order_id, 
        from_status, 
        to_status, 
        changed_on, 
        changed_by, 
        notes
    ) VALUES (
		v_order_id,
        'CREATED',
		'CREATED',
		now(),
        'system',
        'Order has been successfully placed'
    );
     
    INSERT INTO chs_ecom_sales_order_shipping
    (
		order_id, 
        -- shipping_address_id, 
        method, 
        tracking_number, 
        carrier, 
        est_delivery_date, 
        shipping_charge, 
        created_on
    )
    values (
		v_order_id,
        -- NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.shippingAddressId')),'null'),''),
        'STANDARD',
        concat(SUBSTRING_INDEX(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.username')),'null'),''), '-', -1),DATE_FORMAT(NOW(), '%Y%m%d%H%i%s')),
        null,
        DATE_ADD(CURDATE(), INTERVAL 7 DAY),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.shippingCharge')),0.0),''),
        now()
    );
    
        INSERT INTO chs_ecom_sales_order_discounts
    (
		order_id, 
        disc_code, 
        coupon_txn_id, 
        disc_value, 
        created_at
    )
    values (
		v_order_id, 
		(select discount_code from chs_core_marketing_discount_usage where  discount_txn_id= NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),'')),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),0.0),''),
        now()
    );
    
    set v_inventory_model= (NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.inventoryModel')),'null'),''));
    SET i = 0;
SET item_count = JSON_LENGTH(order_json, '$.checkoutDetails.checkoutItems');

WHILE i < item_count DO
 SET v_item_id = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].itemId'))), 'null'), '');
    -- SET @v_qty = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].qty'))), 'null'), '');

	SELECT item_title,item_image,item_slug,item_mrp,item_price,exchange_allowed,subscription_enabled
INTO v_item_title,v_item_image,v_item_slug,v_unit_mrp,v_unit_price,v_exchange_allowed,v_subscription_enabled
FROM chs_ecom_pms_product_card
WHERE item_id = v_item_id 
and inventory_model= v_inventory_model;


    -- Extract returnAllowed (a BOOLEAN value in JSON)
    SET v_return_order = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].returnAllowed'))), 'null'), '');
    SET v_returnable = CASE WHEN v_return_order = 'true' THEN 1 ELSE 0 END;

    INSERT INTO chs_ecom_sales_order_items (
        order_id,
        customer_id,
        product_id,
        item_id,
		item_title ,
		item_image ,
		item_slug ,
        batch_id,
        qty,
        unit_price,
        unit_mrp,
        volume_unit_price,
        volume_unit_mrp,
        tax_amt,
        disc_amount,
        total_price,
        total_mrp,
        return_allowed,
        reserved_qty,
        volume_value,
		exchange_allowed,
        subscription_enabled
    ) VALUES (
        v_order_id,
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].customerId'))), 'null'),''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].productId'))), 'null'), ''),
        v_item_id,
        
        
       v_item_title,v_item_image,v_item_slug,
        
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].batchId'))), 'null'), ''),
        NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].qty'))), 0), ''),
        
		v_unit_price,v_unit_mrp,
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].volumeUnitPrice'))),  ''), 0.0),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].volumeUnitMrp'))), ''), 0.0),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].taxAmt'))),  ''), 0.0),

        
        
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].discAmount'))),  ''), 0.0),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].totalPrice'))),  ''), 0.0),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].totalMrp'))),  ''), 0.0),
        v_returnable,
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].reservedQty'))),  ''), 0.0),
        COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, CONCAT('$.checkoutDetails.checkoutItems[', i, '].volumeValue'))),  ''), 1.0),
		v_exchange_allowed,
        v_subscription_enabled
    );

    SET i = i + 1;

END WHILE;

-- SET v_total_item_weight = (
 --   SELECT SUM(pi.weight_in_gms * oi.qty) FROM chs_ecom_sales_order_items oi
 --   JOIN chs_ecom_pms_product_item pi ON oi.item_id = pi.id WHERE oi.order_id = v_order_id);
 
set v_total_item_weight=0.0;

UPDATE chs_ecom_sales_order_master SET order_weight = v_total_item_weight WHERE id = v_order_id;



    case when JSON_EXTRACT(order_json, '$.shippingAddressId') <> JSON_EXTRACT(order_json, '$.billingAddressId') then
     INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.shippingAddressId');
    SET v_shipping_address_id = LAST_INSERT_ID();

   INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.billingAddressId');
    SET v_billing_address_id = LAST_INSERT_ID();
    
    else 
    INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.shippingAddressId');
    SET v_shipping_address_id = LAST_INSERT_ID();
    set v_billing_address_id = v_shipping_address_id;
    
    end case;
    
INSERT INTO chs_ecom_sales_order_address (
    order_id,
    shipping_address_id,
    billing_address_id
) VALUES (
    v_order_id,
    v_shipping_address_id,
    v_billing_address_id
);
	
    INSERT INTO chs_ecom_sales_order_summary (
    order_num,
    username,
    customer_id,
    full_name,
    email,
    mobile_num,
    order_status,
    total_mrp,
    final_price,
    coupon_disc_amount,
    total_price,
    disc_amount,
    tax_amount,
    shipping_charge,
    payment_status,
    payment_method,
    invoice_url,
    placed_on,
    billing_address,
    shipping_address
)
SELECT 
    om.order_num,
    om.username,
    om.customer_id,
    c.full_name,
    c.email_id,
    c.mobile_number,
    om.order_status,
    om.total_mrp,
    om.final_price,
    om.coupon_disc_amount,
    om.total_price,
    om.disc_amount,
    om.tax_amount,
    om.shipping_charge,
    om.payment_status,
    om.payment_method,
    NULL AS invoice_url,
    om.placed_on,

    -- Billing Address JSON
    (SELECT JSON_OBJECT(
        'fullName', a.full_name,
        'phoneNumber', a.phone_number,
        'addressLine1', a.address_line1,
        'addressLine2', a.address_line2,
        'city', a.city,
        'state', a.state,
        'country', a.country,
        'postalCode', a.postal_code
    )
    FROM chs_core_utils_address_master a 
    WHERE a.id = oa.billing_address_id),

    -- Shipping Address JSON
    (SELECT JSON_OBJECT(
        'fullName', a.full_name,
        'phoneNumber', a.phone_number,
        'addressLine1', a.address_line1,
        'addressLine2', a.address_line2,
        'city', a.city,
        'state', a.state,
        'country', a.country,
        'postalCode', a.postal_code
    )
    FROM chs_core_utils_address_master a 
    WHERE a.id = oa.shipping_address_id)

FROM chs_ecom_sales_order_master om
left JOIN chs_ecom_customer_customer_summary c ON c.customer_id = om.customer_id
JOIN chs_ecom_sales_order_address oa ON oa.order_id = om.id
WHERE om.id = v_order_id;

    
    IF JSON_EXTRACT(order_json, '$.checkoutDetails.cartId') IS NOT NULL THEN
    delete from chs_ecom_sales_cart_items where cart_id=(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.cartId')),'null'),''));
    delete from chs_ecom_sales_cart where id=(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.checkoutDetails.cartId')),'null'),''));
    end if;
    
    
    
    -- Actual else case
    else if exists(select 1 from chs_ecom_sales_order_master where order_num=v_order_num) then
    set v_order_id=(select id from chs_ecom_sales_order_master where order_num=v_order_num);
    if not exists(select 1 from chs_ecom_sales_order_master where id=v_order_id and 
    payment_method=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentMethod')),'null'),'')) then
    update chs_ecom_sales_order_master
    set payment_method=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentMethod')),'null'),'') where id=v_order_id;
    end if;
    
    if not exists(select 1 from chs_ecom_sales_order_discounts where order_id=v_order_id and coupon_txn_id=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),''))
    then
    update chs_ecom_sales_order_discounts
    set coupon_txn_id=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),''), 
    disc_code=(select discount_code from chs_core_marketing_discount_usage
    where discount_txn_id= NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),''))
	,disc_value= NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),'null'),'')
	where order_id=v_order_id;
    
    update chs_ecom_sales_order_master
    set final_price=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.finalPrice')),'null'),'')
    ,coupon_disc_amount=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponDiscAmount')),'null'),'')
    ,amount = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.amount')),'null'),'')
    ,cpg_order_id = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.cpgOrderId')),'null'),'')
    ,wallet_txn_id = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletTxnId')),'null'),'')
    ,wallet_debit_type = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletDebitType')),'null'),'')
    ,wallet_amount = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.walletAmount')),'null'),'')
    ,payment_status = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.paymentStatus')),'null'),'')
    where id=v_order_id;
    end if;
    
    if exists (select 1 from chs_ecom_sales_order_address where JSON_EXTRACT(order_json, '$.billingAddressId')=JSON_EXTRACT(order_json, '$.shippingAddressId') 
    and order_id=v_order_id and (JSON_EXTRACT(order_json, '$.billingAddressId')<>billing_address_id or JSON_EXTRACT(order_json, '$.shippingAddressId')<>shipping_address_id))
    then 
    INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.shippingAddressId');
    SET v_shipping_address_id = LAST_INSERT_ID();
    set v_billing_address_id = v_shipping_address_id;
	
update chs_ecom_sales_order_address
set shipping_address_id=v_shipping_address_id , billing_address_id=v_billing_address_id
where order_id=v_order_id;
		
        else 
        if exists (select 1 from chs_ecom_sales_order_address where order_id=v_order_id and (JSON_EXTRACT(order_json, '$.billingAddressId')<>billing_address_id and JSON_EXTRACT(order_json, '$.shippingAddressId')=shipping_address_id))
    then 
    INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.billingAddressId');
    SET v_billing_address_id = LAST_INSERT_ID();
    update chs_ecom_sales_order_address
set billing_address_id=v_billing_address_id where order_id=v_order_id;
  
  else if exists (select 1 from chs_ecom_sales_order_address where order_id=v_order_id and (JSON_EXTRACT(order_json, '$.billingAddressId')=billing_address_id and JSON_EXTRACT(order_json, '$.shippingAddressId')<>shipping_address_id))
    then 
    INSERT INTO chs_core_utils_address_master (
        full_name, phone_number, address_line1, address_line2, city, state, country, postal_code
    ) select full_name, phone_number, address_line1, address_line2, city, state, country, postal_code from chs_core_utils_address_master 
    where id=JSON_EXTRACT(order_json, '$.shippingAddressId');
    SET v_shipping_address_id = LAST_INSERT_ID();
    update chs_ecom_sales_order_address
set shipping_address_id=v_shipping_address_id where order_id=v_order_id;
end if;
end if;
    end if;
        end if;
        end if;

    update chs_core_marketing_discount_usage set status='APPLIED' where discount_txn_id=NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(order_json, '$.couponTxnId')),'null'),'');
    
    COMMIT;
    
    SELECT JSON_OBJECT(
        'id', om.id,
        'orderNum', om.order_num,
        'cpgOrderId',om.cpg_order_id,
        'username', om.username,
        'customerId', om.customer_id,
        'orderStatus', om.order_status,
        'totalPrice', om.total_price,
        'totalMrp', om.total_mrp,
        'finalPrice',om.final_price,
        'totalItems', om.total_items,
        'totalQty', om.total_qty,
        'discAmount', om.disc_amount,
        'couponDiscAmount',om.coupon_disc_amount,
        'taxAmount', om.tax_amount,
        'shippingCharge', om.shipping_charge,
        'paymentStatus', om.payment_status,
        'paymentMethod', om.payment_method,
        'billingAddressId', oa.billing_address_id,
        'placedOn',DATE_FORMAT(om.placed_on, '%Y-%m-%dT%H:%i:%s'),
        'orderWeight', om.order_weight,
        'amount',om.amount,
        'supplyModel',om.supply_model,
        'orderItems', 
        (SELECT JSON_ARRAYAGG(
            JSON_OBJECT(
                'id', oi.id,
                'orderId', oi.order_id, 
                'customerId',oi.customer_id,
                'productId', oi.product_id, 
                'itemId', oi.item_id, 
                'itemTitle',oi.item_title,
                'itemImage',oi.item_image,
                'item_slug',oi.item_slug,
                'batchId', oi.batch_id, 
                'qty',oi.qty,
                'unitPrice', oi.unit_price,
				'unit_mrp', oi.unit_mrp,
				'volume_unit_price', oi.volume_unit_price,
				'volume_unit_mrp', oi.volume_unit_mrp,
				'tax_amt', oi.tax_amt,
				'total_mrp', oi.total_mrp,
                'discAmount', oi.disc_amount, 
                'totalPrice', oi.total_price,
                'returnAllowed',oi.return_allowed,
                'exchangeAllowed',oi.exchange_allowed,
                'subscriptionEnabled',oi.subscription_enabled
            )
        ) FROM chs_ecom_sales_order_items oi WHERE oi.order_id = om.id)
    ) AS output_json
    FROM chs_ecom_sales_order_master om join chs_ecom_sales_order_address oa on om.id=oa.order_id
	WHERE om.id = v_order_id;

END;


-- deployment: Creating sp_auto_complete...
CREATE PROCEDURE sp_auto_complete (IN p_search_request json)
BEGIN 

	DECLARE v_search_key VARCHAR(100);
    DECLARE v_min_price FLOAT;
    DECLARE v_max_price FLOAT;
    DECLARE v_category_slugs TEXT;
    DECLARE v_offset int;
    DECLARE v_page_size int;
    DECLARE v_page_offset int;
    DECLARE v_row_count int;
    DECLARE v_min float;
    DECLARE v_max float;

	SET v_search_key = REPLACE(TRIM(BOTH ' ' FROM REGEXP_REPLACE(
	LOWER(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.searchKey')),'null'),'')), '[^a-z0-9 ]', '')), ' ', '* +');
	-- SET v_search_key = CONCAT('+ ', v_search_key, ' *');
	 
    SET v_search_key = CONCAT('+', v_search_key, '*');
  
	--  SET v_search_key = CONCAT('%', REGEXP_REPLACE(lower(NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.searchKey')),'null'),'')), '[^a-zA-Z0-9]', ''), '%');

    
    -- SET v_category_slugs = (SELECT GROUP_CONCAT(JSON_UNQUOTE(value))FROM JSON_TABLE(JSON_EXTRACT(p_search_request, '$.categorySlugs'),'$[*]' COLUMNS(value VARCHAR(255) PATH '$')) AS jt);
    SET v_offset = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.offset')),'null'),'');
    SET v_page_size = NULLIF(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(p_search_request, '$.pageSize')),'null'),'');
	SET v_page_offset = v_offset * v_page_size;
    -- select v_search_key;

SELECT JSON_ARRAYAGG(JSON_OBJECT(
                'productId', p.product_id,
                'productCode', p.product_code,
                'productTitle', p.product_title,
                'productSlug', p.product_slug,
                'itemId', p.item_id,
                'itemSlug', p.item_slug,
                'itemTitle', p.item_title,
                'itemMrp', p.item_mrp,
                'itemPrice', p.item_price,
                'itemDiscount', p.item_discount,
                'itemImage', p.item_image,
                'currency', p.currency,
                'minQty', p.min_qty,
                'maxQty', p.max_qty,
                'productStatus', p.product_status,
                'itemStatus', p.item_status,
                'isDefaultItem', p.is_default_item,
                'isDefaultImg', p.is_default_img
        )) as result
FROM (SELECT distinct p1.*
    FROM chs_ecom_pms_product_card p1
    JOIN (
    SELECT DISTINCT p.product_id
    FROM chs_ecom_pms_product_card p
    LEFT JOIN chs_ecom_pms_cat_prod_map cp ON p.product_id = cp.product_id
    LEFT JOIN chs_ecom_pms_category c ON cp.category_id = c.id
    LEFT JOIN chs_ecom_pms_section s ON c.section_id = s.id
    left join chs_ecom_pms_search_keywords sk on sk.product_id = p.product_id
    WHERE -- p.is_default_item = 1 AND
    p.product_status = 'ACTIVE' AND p.item_status = 'ACTIVE'
    AND p.is_default_img = 1 
        AND (
            MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE)
            OR MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE)
			OR MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE)
           -- OR MATCH(c.title, c.slug) AGAINST(v_search_key IN BOOLEAN MODE)
           -- OR MATCH(s.title, s.slug) AGAINST(v_search_key IN BOOLEAN MODE)
        )
    ORDER BY 
        MATCH(p.product_title, p.product_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
        MATCH(p.item_title, p.item_slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
		MATCH(sk.keyword) AGAINST(v_search_key IN BOOLEAN MODE) desc,
      --  MATCH(c.title, c.slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
      --  MATCH(s.title, s.slug) AGAINST(v_search_key IN BOOLEAN MODE) DESC,
        p.product_title
    LIMIT v_page_size OFFSET v_page_offset
) AS distinct_products ON p1.product_id = distinct_products.product_id WHERE p1.is_default_item = 1 AND
    p1.product_status = 'ACTIVE' AND p1.item_status = 'ACTIVE'
    AND p1.is_default_img = 1) AS p;


  end;


-- deployment: Creating sp_add_stock...
CREATE PROCEDURE sp_add_stock (IN p_request json)
BEGIN

    /* Declare Variables */
    DECLARE v_warehouse_id BIGINT;
    DECLARE v_storage_id BIGINT;
    DECLARE v_storage_code VARCHAR(50);
    DECLARE v_sku_code VARCHAR(50);
    DECLARE v_batch_id BIGINT;
    DECLARE v_qty INT;
    DECLARE v_ref_type VARCHAR(20);
    DECLARE v_ref_id BIGINT;
    DECLARE v_reason VARCHAR(255);
    DECLARE v_cost_price DECIMAL(10,2);
    DECLARE v_total_value DECIMAL(16,2);
    DECLARE v_expiry_date date;
    DECLARE v_sku_exists INT DEFAULT 0;
    DECLARE v_success INT DEFAULT 1;

DECLARE EXIT HANDLER FOR SQLEXCEPTION
BEGIN
    ROLLBACK;
    SET v_success = 0;
END;

START TRANSACTION;

    /* 1️⃣ Extract JSON Fields */
    SET v_warehouse_id   = JSON_EXTRACT(p_request, '$.warehouseId');
    SET v_storage_id     = JSON_EXTRACT(p_request, '$.warehouseStorageId');
    SET v_storage_code   = JSON_UNQUOTE(JSON_EXTRACT(p_request, '$.storageCode'));
    SET v_sku_code        = JSON_UNQUOTE(JSON_EXTRACT(p_request, '$.skuCode'));
    SET v_batch_id        = JSON_EXTRACT(p_request, '$.batchId');
    SET v_qty             = JSON_EXTRACT(p_request, '$.qty');
    SET v_ref_type         = JSON_UNQUOTE(JSON_EXTRACT(p_request, '$.referenceType'));
    SET v_ref_id            = JSON_EXTRACT(p_request, '$.referenceId');
    SET v_reason            = JSON_UNQUOTE(JSON_EXTRACT(p_request, '$.reason'));
    SET v_expiry_date = (select expiry_date from chs_ecom_wms_batch_master where sku_code=v_sku_code and id=v_batch_id);

    /* 2️⃣ Get Cost Price */
    SELECT cost_price
    INTO v_cost_price
    FROM chs_ecom_wms_sku_cost_price
    WHERE sku_code = v_sku_code
      AND batch_id = v_batch_id;

    IF v_cost_price IS NULL THEN
        SET v_cost_price = 0.00;
    END IF;

    /* 3️⃣ Insert / Update Warehouse Stock (location level) */
/* Check if record exists */
IF EXISTS (
    SELECT 1 
    FROM chs_ecom_wms_warehouse_stock
    WHERE warehouse_id = v_warehouse_id
      AND warehouse_storage_id = v_storage_id
      AND sku_code = v_sku_code
      AND batch_id = v_batch_id
) THEN
    UPDATE chs_ecom_wms_warehouse_stock
    SET qty = qty + v_qty
    WHERE warehouse_id = v_warehouse_id AND warehouse_storage_id = v_storage_id AND sku_code = v_sku_code AND batch_id = v_batch_id;
ELSE
    INSERT INTO chs_ecom_wms_warehouse_stock (warehouse_id, warehouse_storage_id, sku_code, batch_id, qty, expiry_date)
    VALUES (v_warehouse_id, v_storage_id, v_sku_code, v_batch_id, v_qty, v_expiry_date);
END IF;


    /* 4️⃣ Insert / Update Warehouse Stock Summary */
    IF EXISTS (
    SELECT 1
    FROM chs_ecom_wms_warehouse_stock_summary
    WHERE warehouse_id = v_warehouse_id
      AND sku_code = v_sku_code
      AND batch_id = v_batch_id
) THEN
    UPDATE chs_ecom_wms_warehouse_stock_summary
    SET total_qty = total_qty + v_qty,
        available_qty = available_qty + v_qty,
        cost_price = v_cost_price,
        last_movement_on = NOW()
    WHERE warehouse_id = v_warehouse_id
      AND sku_code = v_sku_code
      AND batch_id = v_batch_id;
ELSE
    INSERT INTO chs_ecom_wms_warehouse_stock_summary
    (warehouse_id, sku_code, batch_id, total_qty, reserved_qty, available_qty,expiry_date, cost_price, last_movement_on)
    VALUES
    (v_warehouse_id, v_sku_code, v_batch_id, v_qty, 0, v_qty,v_expiry_date, v_cost_price, NOW());
END IF;


    /* 5️⃣ Stock Movement Log */
    INSERT INTO chs_ecom_wms_stock_transfer
    (warehouse_id, storage_code, sku, batch_id, movement_type, qty, reference_type, reference_id, reason)
    VALUES (v_warehouse_id, v_storage_code, v_sku_code, v_batch_id, 'IN', v_qty, v_ref_type, v_ref_id, v_reason);

    /* 6️⃣ Storage Value Summary */
    SET v_total_value = v_qty * v_cost_price;

    IF EXISTS (
    SELECT 1
    FROM chs_ecom_wms_storage_value_summary
    WHERE warehouse_id = v_warehouse_id
      AND storage_code = v_storage_code
) THEN
    UPDATE chs_ecom_wms_storage_value_summary
    SET total_qty = total_qty + v_qty,
        total_value = total_value + v_total_value
    WHERE warehouse_id = v_warehouse_id
      AND storage_code = v_storage_code;
ELSE
    INSERT INTO chs_ecom_wms_storage_value_summary
    (warehouse_id, storage_code, total_qty, total_value)
    VALUES
    (v_warehouse_id, v_storage_code, v_qty, v_total_value);
END IF;

IF EXISTS (
    SELECT 1
    FROM chs_ecom_wms_warehouse_value_summary
    WHERE warehouse_id = v_warehouse_id
) THEN
    UPDATE chs_ecom_wms_warehouse_value_summary
    SET total_qty = total_qty + v_qty,
        total_inventory_value = total_inventory_value + v_total_value,
        total_sku_count = total_sku_count + IF(v_sku_exists = 0, 1, 0),
        last_stock_movement_on = NOW(),
        last_calculated_on = NOW(),
        modified_on = NOW(),
        modified_by = 'SYSTEM'
    WHERE warehouse_id = v_warehouse_id;
ELSE
    INSERT INTO chs_ecom_wms_warehouse_value_summary
    (
        warehouse_id,
        total_sku_count,
        total_qty,
        total_inventory_value,
        expired_stock_value,
        blocked_stock_value,
        last_stock_movement_on,
        last_calculated_on,
        created_on,
        created_by
    )
    VALUES
    (
        v_warehouse_id,
        1,
        v_qty,
        v_total_value,
        0.00,
        0.00,
        NOW(),
        NOW(),
        NOW(),
        'SYSTEM'
    );
END IF;

IF v_success = 1 THEN
    COMMIT;
END IF;

SELECT v_success AS result;


END;


